  if (req.method === "GET" && pathname === "/api/admin/ikas/connect") {
    const startedAt = Date.now();
    try {
      if (ikasSummaryCache.value) {
        const cached = ikasSummaryCache.value;
        const hasData = Boolean(((cached.orders || []).length) || ((cached.products || []).length) || ((cached.collections || []).length) || ((cached.readyOrders || []).length) || ((cached.readyProductTotals || []).length));
        if (cached.connected && hasData && !cached.ikasError) {
          return sendJson(res, {
            ok: true,
            connected: true,
            verified: true,
            cached: true,
            status: "verified",
            message: "Bağlandı",
            elapsedMs: Date.now() - startedAt
          });
        }
      }

      if (!ikasConfigured()) {
        return sendJson(res, {
          ok: true,
          connected: false,
          status: "env_missing",
          message: "ikas env değerleri eksik."
        });
      }

      const quickErrors = [];
      await withTimeout((async () => {
        await getIkasAccessToken();

        let orderOk = false;
        let productOk = false;

        try {
          await ikasGraphQL(`query RuthQuickOrder { listOrder(pagination: { limit: 1, page: 1 }) { count data { id orderNumber } } }`, {}, "ikas quick order");
          orderOk = true;
        } catch (error) {
          quickErrors.push(error && error.message ? error.message : String(error));
        }

        try {
          await ikasGraphQL(`query RuthQuickProduct { listProduct(pagination: { limit: 1, page: 1 }) { count data { id name } } }`, {}, "ikas quick product");
          productOk = true;
        } catch (error) {
          quickErrors.push(error && error.message ? error.message : String(error));
        }

        if (!orderOk && !productOk) {
          throw new Error(quickErrors.join(" || ").slice(0, 900) || "ikas gerçek veri sorgusu başarısız");
        }
      })(), 5000, "ikas bağlantısı 5 saniye içinde tamamlanamadı");

      ikasLastWarm = { ok: true, at: new Date().toISOString(), error: "" };

      setTimeout(() => {
        warmIkasSummary("quick-connect").catch(() => {});
      }, 50);

      return sendJson(res, {
        ok: true,
        connected: true,
        verified: true,
        status: "verified",
        message: "ikas bağlantısı doğrulandı, veriler yükleniyor",
        elapsedMs: Date.now() - startedAt
      });
    } catch (error) {
      ikasLastWarm = { ok: false, at: new Date().toISOString(), error: error && error.message ? error.message : String(error) };
      setTimeout(() => {
        warmIkasSummary("quick-connect-retry").catch(() => {});
      }, 1500);
      return sendJson(res, {
        ok: true,
        connected: false,
        status: "connecting",
        message: "Bağlanıyor",
        error: ikasLastWarm.error,
        elapsedMs: Date.now() - startedAt
      });
    }
  }

