async function fetchIkasCategories() {
  if (!ikasConfigured()) return [];
  const queries = [
    { label: "ikas categories full", query: `query RuthListCategories { listCategory { id name imageId parentId categoryPath categoryPathItems { id name } } }` },
    { label: "ikas categories safe", query: `query RuthListCategoriesSafe { listCategory { id name parentId categoryPath } }` },
    { label: "ikas categories minimal", query: `query RuthListCategoriesMinimal { listCategory { id name } }` }
  ];
  const errors = [];
  for (const attempt of queries) {
    try {
      const data = await ikasGraphQL(attempt.query, {}, attempt.label);
      const rows = Array.isArray(data && data.listCategory) ? data.listCategory : [];
      return rows.map((category) => ({
        id: valueOrEmpty(category.id),
        name: valueOrEmpty(category.name) || "Koleksiyon",
        parentId: valueOrEmpty(category.parentId),
        imageId: valueOrEmpty(category.imageId),
        image: buildIkasImageUrl(category.imageId),
        categoryPath: Array.isArray(category.categoryPath) ? category.categoryPath : [],
        categoryPathItems: Array.isArray(category.categoryPathItems) ? category.categoryPathItems.map((item) => ({ id: valueOrEmpty(item.id), name: valueOrEmpty(item.name) })) : []
      })).filter((category) => category.id || category.name);
    } catch (error) {
      errors.push(error && error.message ? error.message : String(error));
    }
  }
  console.error("ikas categories error:", errors.join(" || ").slice(0, 900));
  return [];
}



function normalizeIkasVariantTypeRows(input) {
  const raw = Array.isArray(input)
    ? input
    : (input && Array.isArray(input.data))
      ? input.data
      : input
        ? [input]
        : [];

  return raw.map((type) => {
    const values = Array.isArray(type && type.values)
      ? type.values.map((value) => ({
          id: valueOrEmpty(value.id),
          name: valueOrEmpty(value.name),
          colorCode: valueOrEmpty(value.colorCode),
          thumbnailImageId: valueOrEmpty(value.thumbnailImageId)
        })).filter((value) => value.id || value.name)
      : [];

    return {
      id: valueOrEmpty(type && type.id),
      name: valueOrEmpty(type && type.name) || "Varyant",
      order: Number((type && type.order) || 0),
      selectionType: valueOrEmpty(type && type.selectionType),
      values
    };
  }).filter((type) => type.id || type.name);
}

function buildIkasVariantTypeMap(types) {
  const map = new Map();
  (types || []).forEach((type) => {
    const valuesById = new Map();
    (type.values || []).forEach((value) => {
      if (value.id) valuesById.set(String(value.id), value);
    });
    map.set(String(type.id), { ...type, valuesById });
  });
  return map;
}

async function fetchIkasVariantTypes() {
  if (!ikasConfigured()) return [];
  try {
    const query = `
      query {
        listVariantType {
          id
          name
          selectionType
          values {
            id
            name
            colorCode
            thumbnailImageId
          }
        }
      }
    `;
    const data = await ikasGraphQL(query, {}, "ikas variant types");
    return normalizeIkasVariantTypeRows(data && data.listVariantType);
  } catch (error) {
    console.error("ikas variant types error:", error && error.message ? error.message.slice(0, 900) : error);
    return [];
  }
}

function extractIkasVariantPrice(prices) {
  const list = Array.isArray(prices) ? prices : (prices ? [prices] : []);
  const firstWithDiscount = list.find((item) => Number(item && item.discountPrice) > 0);
  const firstWithSell = list.find((item) => Number(item && item.sellPrice) > 0);
  const first = firstWithDiscount || firstWithSell || list[0] || {};
  return {
    sellPrice: Number(first.sellPrice || first.price || first.amount || 0),
    discountPrice: Number(first.discountPrice || first.discountedPrice || 0)
  };
}


function extractIkasImageHint(item) {
  const value = item || {};
  const direct =
    valueOrEmpty(value.imageUrl) ||
    valueOrEmpty(value.url) ||
    valueOrEmpty(value.src) ||
    valueOrEmpty(value.originalSrc) ||
    valueOrEmpty(value.thumbnailUrl) ||
    valueOrEmpty(value.previewUrl) ||
    "";
  if (direct) return direct;

  const nested =
    value.mainImage ||
    value.image ||
    value.thumbnailImage ||
    value.thumbnail ||
    null;
  if (nested && typeof nested === "object") {
    const nestedUrl = extractIkasImageHint(nested);
    if (nestedUrl) return nestedUrl;
  }

  const images = Array.isArray(value.images) ? value.images : [];
  for (const image of images) {
    const found = extractIkasImageHint(image);
    if (found) return found;
  }

  const id = valueOrEmpty(value.mainImageId || value.imageId || value.fileId || value.thumbnailImageId);
  return buildIkasImageUrl(id);
}

function normalizeIkasProductImageHints(rows) {
  return (Array.isArray(rows) ? rows : []).map((product) => ({
    id: valueOrEmpty(product && product.id),
    name: valueOrEmpty(product && product.name),
    slug: valueOrEmpty(product && (product.slug || product.handle)),
    image: extractIkasImageHint(product),
    mainImageId: valueOrEmpty(product && (product.mainImageId || product.imageId || product.fileId)),
    variants: Array.isArray(product && product.variants) ? product.variants.map((variant) => ({
      id: valueOrEmpty(variant && variant.id),
      sku: valueOrEmpty(variant && variant.sku),
      image: extractIkasImageHint(variant),
      mainImageId: valueOrEmpty(variant && (variant.mainImageId || variant.imageId || variant.fileId))
    })).filter((variant) => variant.id || variant.sku || variant.image) : []
  })).filter((product) => product.id || product.name || product.image || product.slug);
}

async function fetchIkasProductImageHints() {
  if (!ikasConfigured()) return [];
  const attempts = [
    {
      label: "ikas product image hints full",
      fields: `
        id
        name
        slug
        mainImageId
        imageId
        images { id imageId fileId url imageUrl }
        variants {
          id
          sku
          mainImageId
          imageId
          images { id imageId fileId url imageUrl }
        }
      `
    },
    {
      label: "ikas product image hints mainImage",
      fields: `
        id
        name
        slug
        mainImageId
        variants { id sku mainImageId }
      `
    },
    {
      label: "ikas product image hints slug",
      fields: `
        id
        name
        slug
        variants { id sku }
      `
    }
  ];

  const errors = [];
  for (const attempt of attempts) {
    try {
      const rows = await fetchIkasPaginatedList({
        label: attempt.label,
        rootField: "listProduct",
        fields: attempt.fields,
        normalize: normalizeIkasProductImageHints,
        maxPages: 180
      });
      if (Array.isArray(rows)) return rows;
    } catch (error) {
      errors.push(`${attempt.label}: ${error && error.message ? error.message : String(error)}`);
    }
  }
  if (errors.length && String(process.env.IKAS_IMAGE_DEBUG_LOGS || "0") === "1") {
    console.error("ikas product image hint attempts failed:", errors.join(" || ").slice(0, 1800));
  }
  return [];
}

function mergeIkasProductImageHints(products, hints) {
  const byId = new Map();
  const byName = new Map();
  const byVariantId = new Map();
  (Array.isArray(hints) ? hints : []).forEach((hint) => {
    if (hint.id) byId.set(String(hint.id), hint);
    if (hint.name) byName.set(normalizeLookupText(hint.name), hint);
    (hint.variants || []).forEach((variant) => {
      if (variant.id) byVariantId.set(String(variant.id), variant);
    });
  });

  return (Array.isArray(products) ? products : []).map((product) => {
    const hint = byId.get(String(product.id || "")) || byName.get(normalizeLookupText(product.name || "")) || null;
    const next = { ...product };
    if (hint) {
      if (!next.slug && hint.slug) next.slug = hint.slug;
      if (!next.image && hint.image) next.image = hint.image;
      if (!next.mainImageId && hint.mainImageId) next.mainImageId = hint.mainImageId;
    }
    next.variants = (next.variants || []).map((variant) => {
      const vh = byVariantId.get(String(variant.id || ""));
      if (!vh) return variant;
      return {
        ...variant,
        image: variant.image || vh.image || "",
        mainImageId: variant.mainImageId || vh.mainImageId || "",
        sku: variant.sku || vh.sku || ""
      };
    });
    if (!next.image) next.image = (next.variants || []).find((variant) => variant.image)?.image || "";
    return next;
  });
}


async function fetchIkasProducts(categories = []) {
  if (!ikasConfigured()) return [];
  const categoryMap = new Map((categories || []).map((category) => [String(category.id), category]));
  const variantTypes = await fetchIkasVariantTypes();
  const variantTypeMap = buildIkasVariantTypeMap(variantTypes);
  const normalize = (rows) => normalizeIkasProducts(rows, categoryMap, variantTypeMap);

  const attempts = [
    {
      label: "ikas products mapped-variants-prices",
      fields: `
        id
        name
        categoryIds
        productVariantTypes {
          order
          variantTypeId
          variantValueIds
        }
        variants {
          id
          sku
          variantValueIds {
            variantTypeId
            variantValueId
          }
          prices { sellPrice discountPrice }
        }
      `
    },
    {
      label: "ikas products mapped-variants-no-prices",
      fields: `
        id
        name
        categoryIds
        productVariantTypes {
          order
          variantTypeId
          variantValueIds
        }
        variants {
          id
          sku
          variantValueIds {
            variantTypeId
            variantValueId
          }
        }
      `
    },
    {
      label: "ikas products variants-prices-only",
      fields: `
        id
        name
        categoryIds
        variants {
          id
          sku
          prices { sellPrice discountPrice }
        }
      `
    },
    {
      label: "ikas products variants-id-only",
      fields: `
        id
        name
        categoryIds
        variants {
          id
          sku
        }
      `
    },
    {
      label: "ikas products categoryIds-only",
      fields: `
        id
        name
        categoryIds
      `
    },
    {
      label: "ikas products minimal-only",
      fields: `
        id
        name
      `
    }
  ];

  const errors = [];
  for (const attempt of attempts) {
    try {
      const products = await fetchIkasPaginatedList({
        label: attempt.label,
        rootField: "listProduct",
        fields: attempt.fields,
        normalize,
        maxPages: 180
      });
      if (Array.isArray(products)) return products;
    } catch (error) {
      const msg = `${attempt.label}: ${error && error.message ? error.message : String(error)}`;
      errors.push(msg);
      console.error("ikas product attempt failed:", msg.slice(0, 900));
    }
  }

  console.error("ikas products error:", errors.join(" || ").slice(0, 1800));
  return [];
}

function normalizeIkasProducts(rawProducts, categoryMap = new Map(), variantTypeMap = new Map()) {
  return rawProducts.map((product) => {
    const categoryIds = Array.isArray(product.categoryIds)
      ? product.categoryIds.map(valueOrEmpty).filter(Boolean)
      : [];

    const directCategories = Array.isArray(product.categories)
      ? product.categories.map((category) => ({
          id: valueOrEmpty(category.id),
          name: valueOrEmpty(category.name) || "Kategori",
          image: buildIkasImageUrl(category.imageId),
          imageId: valueOrEmpty(category.imageId)
        })).filter((category) => category.id || category.name)
      : [];

    const categories = directCategories.length
      ? directCategories
      : categoryIds.map((id) => {
          const found = categoryMap.get(id);
          return found || { id, name: `Kategori ${id.slice(0, 6)}`, image: "", imageId: "" };
        }).filter((category) => category.id || category.name);

    const productVariantTypes = Array.isArray(product.productVariantTypes)
      ? product.productVariantTypes.map((type, index) => {
          const typeId = valueOrEmpty(type.variantTypeId);
          const found = variantTypeMap.get(typeId);
          const values = Array.isArray(type.variantValueIds)
            ? type.variantValueIds.map((valueId) => {
                const value = found && found.valuesById ? found.valuesById.get(String(valueId)) : null;
                return {
                  id: valueOrEmpty(valueId),
                  name: valueOrEmpty(value && value.name) || valueOrEmpty(valueId),
                  colorCode: valueOrEmpty(value && value.colorCode),
                  thumbnailImageId: valueOrEmpty(value && value.thumbnailImageId)
                };
              }).filter((value) => value.id || value.name)
            : [];
          return {
            order: Number(type.order || index),
            variantTypeId: typeId,
            name: valueOrEmpty(found && found.name) || (typeId ? `Varyant ${index + 1}` : "Varyant"),
            selectionType: valueOrEmpty(found && found.selectionType),
            values
          };
        }).filter((type) => type.variantTypeId || type.values.length)
      : [];

    const variants = Array.isArray(product.variants) ? product.variants.map((variant) => {
      const relationPairs = Array.isArray(variant.variantValueIds)
        ? variant.variantValueIds.map((relation) => {
            const typeId = valueOrEmpty(relation && relation.variantTypeId);
            const valueId = valueOrEmpty(relation && relation.variantValueId);
            const type = variantTypeMap.get(typeId);
            const value = type && type.valuesById ? type.valuesById.get(valueId) : null;
            return {
              variantTypeId: typeId,
              variantValueId: valueId,
              variantTypeName: valueOrEmpty(type && type.name) || (typeId ? `Varyant ${typeId.slice(0, 6)}` : "Varyant"),
              variantValueName: valueOrEmpty(value && value.name) || valueId,
              colorCode: valueOrEmpty(value && value.colorCode),
              thumbnailImageId: valueOrEmpty(value && value.thumbnailImageId)
            };
          }).filter((value) => value.variantValueId || value.variantValueName)
        : [];

      const legacyPairs = Array.isArray(variant.variantValues)
        ? variant.variantValues.map((value) => ({
            variantTypeId: "",
            variantValueId: "",
            variantTypeName: valueOrEmpty(value.variantTypeName),
            variantValueName: valueOrEmpty(value.variantValueName),
            colorCode: "",
            thumbnailImageId: ""
          })).filter((value) => value.variantValueName)
        : [];

      const variantValues = relationPairs.length ? relationPairs : legacyPairs;
      const variantText = variantValues.length
        ? variantValues.map((value) => {
            const left = valueOrEmpty(value.variantTypeName);
            const right = valueOrEmpty(value.variantValueName);
            return right ? (left ? `${left}: ${right}` : right) : "";
          }).filter(Boolean).join(" / ")
        : "";

      const stockFromStocks = Array.isArray(variant.stocks)
        ? variant.stocks.reduce((sum, item) => sum + Number(item.stockCount || 0), 0)
        : 0;
      const priceInfo = extractIkasVariantPrice(variant.prices);

      return {
        id: valueOrEmpty(variant.id),
        name: valueOrEmpty(product.name) || "Ürün",
        sku: valueOrEmpty(variant.sku),
        barcode: Array.isArray(variant.barcodeList) ? variant.barcodeList.join(", ") : "",
        mainImageId: "",
        image: "",
        productId: valueOrEmpty(product.id),
        slug: "",
        variantText,
        variantValues,
        variantValueIds: Array.isArray(variant.variantValueIds)
          ? variant.variantValueIds.map((relation) => ({
              variantTypeId: valueOrEmpty(relation && relation.variantTypeId),
              variantValueId: valueOrEmpty(relation && relation.variantValueId)
            })).filter((relation) => relation.variantValueId || relation.variantTypeId)
          : [],
        sellPrice: priceInfo.sellPrice,
        discountPrice: priceInfo.discountPrice,
        stock: stockFromStocks,
        isActive: typeof variant.isActive === "boolean" ? variant.isActive : true
      };
    }) : [];

    const image = "";
    return {
      id: valueOrEmpty(product.id),
      name: valueOrEmpty(product.name) || "Ürün",
      slug: "",
      image,
      mainImageId: "",
      totalStock: Number(product.totalStock || variants.reduce((sum, variant) => sum + Number(variant.stock || 0), 0) || 0),
      categoryIds: categoryIds.length ? categoryIds : categories.map((category) => category.id).filter(Boolean),
      categories,
      variantTypes: productVariantTypes.sort((a, b) => Number(a.order || 0) - Number(b.order || 0)),
      variants,
      createdAt: normalizeIkasDate(product.createdAt),
      updatedAt: normalizeIkasDate(product.updatedAt)
    };
  }).filter((product) => product.id || product.name);
}

function mergeOrderImagesIntoProducts(products, orders) {
  const byProductId = new Map();
  const byVariantId = new Map();
  orders.forEach((order) => {
    (order.items || []).forEach((item) => {
      if (item.productId && (item.image || item.mainImageId)) {
        const old = byProductId.get(item.productId) || {};
        byProductId.set(item.productId, { ...old, image: item.image, mainImageId: item.mainImageId });
      }
      if (item.variantId && (item.image || item.mainImageId || Number(item.unitPrice || item.totalPrice) > 0)) {
        const old = byVariantId.get(item.variantId) || {};
        byVariantId.set(item.variantId, {
          ...old,
          image: item.image || old.image || "",
          mainImageId: item.mainImageId || old.mainImageId || "",
          unitPrice: Number(item.unitPrice || (Number(item.totalPrice || 0) / Math.max(1, Number(item.quantity || 1))) || old.unitPrice || 0)
        });
      }
    });
  });
  return products.map((product) => {
    let next = { ...product };
    const fromProduct = byProductId.get(product.id);
    if (!next.image && fromProduct) {
      next.image = fromProduct.image || buildIkasImageUrl(fromProduct.mainImageId);
      next.mainImageId = next.mainImageId || fromProduct.mainImageId || "";
    }
    next.variants = (next.variants || []).map((variant) => {
      const fromVariant = byVariantId.get(variant.id);
      if (!fromVariant) return variant;
      const patched = { ...variant };
      if (!patched.image && (fromVariant.image || fromVariant.mainImageId)) {
        patched.image = fromVariant.image || buildIkasImageUrl(fromVariant.mainImageId);
        patched.mainImageId = patched.mainImageId || fromVariant.mainImageId || "";
      }
      if (!Number(patched.sellPrice || 0) && Number(fromVariant.unitPrice || 0) > 0) {
        patched.sellPrice = Number(fromVariant.unitPrice || 0);
      }
      return patched;
    });
    if (!next.image) next.image = (next.variants || []).find((variant) => variant.image)?.image || "";
    return next;
  });
}

function enrichOrdersWithProducts(orders, products) {
  const byVariantId = new Map();
  const byProductId = new Map();
  const bySku = new Map();
  (products || []).forEach((product) => {
    if (product && product.id) byProductId.set(String(product.id), product);
    (product.variants || []).forEach((variant) => {
      if (variant && variant.id) byVariantId.set(String(variant.id), { product, variant });
      if (variant && variant.sku) bySku.set(String(variant.sku).toLocaleLowerCase("tr"), { product, variant });
      (variant.bundleProducts || []).forEach((child) => {
        if (child && child.variantId && !byVariantId.has(String(child.variantId))) byVariantId.set(String(child.variantId), { product: byProductId.get(String(child.productId)) || child, variant: child });
        if (child && child.sku && !bySku.has(String(child.sku).toLocaleLowerCase("tr"))) bySku.set(String(child.sku).toLocaleLowerCase("tr"), { product: byProductId.get(String(child.productId)) || child, variant: child });
      });
    });
  });

  function enrichOne(item) {
    const foundByVariant = item.variantId ? byVariantId.get(String(item.variantId)) : null;
    const foundBySku = !foundByVariant && item.sku ? bySku.get(String(item.sku).toLocaleLowerCase("tr")) : null;
    const found = foundByVariant || foundBySku || null;
    const product = found ? found.product : (item.productId ? byProductId.get(String(item.productId)) : null);
    let next = item;
    if (product) {
      const baseName = item.baseName && item.baseName !== "Ürün" ? item.baseName : (product.name || item.baseName || item.name || "Ürün");
      const variantText = item.variantText || (found && found.variant && found.variant.variantText) || "";
      next = {
        ...item,
        productId: item.productId || product.id || "",
        baseName,
        variantText,
        name: variantText && !item.isBundle ? `${baseName} — ${variantText}` : baseName,
        image: item.image || product.image || (found && found.variant && found.variant.image) || "",
        mainImageId: item.mainImageId || product.mainImageId || (found && found.variant && found.variant.mainImageId) || "",
        categories: item.categories && item.categories.length ? item.categories : (product.categories || []),
        sku: item.sku || (found && found.variant && found.variant.sku) || ""
      };
    }
    if (next && Array.isArray(next.bundleItems) && next.bundleItems.length) {
      next = {
        ...next,
        isBundle: true,
        bundleItems: next.bundleItems.map(enrichOne)
      };
    }
    return next;
  }

  return (orders || []).map((order) => {
    const nextOrder = { ...order };
    nextOrder.items = (order.items || []).map(enrichOne);
    return nextOrder;
  });
}

function buildCollectionsFromProducts(products, categories = []) {
  const map = new Map();
  (categories || []).forEach((category) => {
    const key = category.id || category.name || "uncategorized";
    if (!map.has(key)) {
      map.set(key, { id: key, name: category.name || "Koleksiyon", image: category.image || "", imageId: category.imageId || "", productCount: 0, products: [] });
    }
  });

  products.forEach((product) => {
    const productCategories = product.categories && product.categories.length ? product.categories : [{ id: "uncategorized", name: "Koleksiyonsuz", image: "", imageId: "" }];
    productCategories.forEach((category) => {
      const key = category.id || category.name || "uncategorized";
      const existing = map.get(key) || { id: key, name: category.name || "Koleksiyonsuz", image: category.image || product.image || "", imageId: category.imageId || "", productCount: 0, products: [] };
      existing.productCount += 1;
      existing.products.push({ id: product.id, name: product.name, image: product.image, totalStock: product.totalStock });
      if (!existing.image && (category.image || product.image)) existing.image = category.image || product.image;
      map.set(key, existing);
    });
  });
  return [...map.values()].filter((item) => item.productCount || item.id !== "uncategorized").sort((a, b) => Number(b.productCount || 0) - Number(a.productCount || 0) || String(a.name).localeCompare(String(b.name), "tr"));
}

async function buildIkasSummary(options = {}) {
  const cacheMs = Math.max(0, Number(process.env.IKAS_SUMMARY_CACHE_MS || 300000));
  const now = Date.now();
  const staleOk = Boolean(options && options.staleOk);

  if (ikasSummaryCache.value) {
    const isFresh = !cacheMs || ikasSummaryCache.expiresAt > now;
    if (isFresh || staleOk) {
      if (!isFresh && staleOk && !ikasSummaryInFlight) {
        ikasSummaryInFlight = buildIkasSummaryFresh().finally(() => {
          ikasSummaryInFlight = null;
        });
      }
      return {
        ...ikasSummaryCache.value,
        stale: !isFresh,
        refreshing: Boolean(ikasSummaryInFlight)
      };
    }
  }

  if (ikasSummaryInFlight) {
    return await ikasSummaryInFlight;
  }

  ikasSummaryInFlight = buildIkasSummaryFresh().finally(() => {
    ikasSummaryInFlight = null;
  });
  return await ikasSummaryInFlight;
}

async function warmIkasSummary(reason = "auto") {
  if (!ikasConfigured()) {
    ikasLastWarm = { ok: false, at: new Date().toISOString(), error: "IKAS env eksik" };
    console.log("ikas auto connect skipped:", ikasLastWarm.error);
    return null;
  }
  try {
    const summary = await buildIkasSummary();
    ikasLastWarm = { ok: true, at: new Date().toISOString(), error: "" };
    console.log(`ikas auto connected (${reason}): ${Number((summary.orders || []).length)} orders, ${Number((summary.products || []).length)} products`);
    return summary;
  } catch (error) {
    ikasLastWarm = { ok: false, at: new Date().toISOString(), error: error && error.message ? error.message : String(error) };
    console.error(`ikas auto connect failed (${reason}):`, ikasLastWarm.error);
    return null;
  }
}

async function buildIkasSummaryFresh() {
  const cacheMs = Math.max(0, Number(process.env.IKAS_SUMMARY_CACHE_MS || 300000));
  if (!ikasConfigured()) {
    return {
      connected: false,
      totals: { orders: 0, units: 0, readyOrders: 0, readyUnits: 0, deliveredOrders: 0, revenue: 0, products: 0, collections: 0 },
      productTotals: [],
      readyProductTotals: [],
      orders: [],
      readyOrders: [],
      deliveredOrders: [],
      products: [],
      collections: [],
      message: "ikas env değerleri bekleniyor."
    };
  }

  let orders = [];
  let products = [];
  let categories = [];
  let orderError = "";
  let productError = "";
  let categoryError = "";

  try {
    orders = await fetchIkasOrders();
  } catch (error) {
    orderError = error && error.message ? error.message : "siparişler çekilemedi";
    console.error("ikas orders error:", orderError);
    orders = [];
  }

  try {
    categories = await fetchIkasCategories();
  } catch (error) {
    categoryError = error && error.message ? error.message : "koleksiyonlar çekilemedi";
    console.error("ikas categories error:", categoryError);
    categories = [];
  }

  try {
    products = await fetchIkasProducts(categories);
  } catch (error) {
    productError = error && error.message ? error.message : "ürünler çekilemedi";
    console.error("ikas products error:", productError);
    products = [];
  }

  try {
    const imageHints = await fetchIkasProductImageHints();
    products = mergeIkasProductImageHints(products, imageHints);
  } catch (error) {
    if (String(process.env.IKAS_IMAGE_DEBUG_LOGS || "0") === "1") {
      console.error("ikas product image hint merge error:", error && error.message ? error.message : error);
    }
  }

  orders = enrichOrdersWithProducts(orders, products);
  products = mergeOrderImagesIntoProducts(products, orders);
  if (IKAS_FETCH_STOREFRONT_IMAGES) {
    await enrichIkasImagesDirectFromProductPages(orders, products, categories);
    await enrichIkasImagesFromStorefront(orders, products, categories);
  }
  orders = enrichOrdersWithProducts(orders, products);
  products = mergeOrderImagesIntoProducts(products, orders);
  const collections = buildCollectionsFromProducts(products, categories);
  const readyOrders = orders.filter(isReadyOrder).sort(orderNewestFirst);
  const deliveredOrders = orders.filter(isDeliveredOrder).sort(orderNewestFirst);
  const readyProductTotals = buildReadyProductTotals(readyOrders);
  const units = orders.reduce((sum, order) => sum + order.items.reduce((s, item) => s + Number(item.quantity || 0), 0), 0);
  const readyUnits = readyOrders.reduce((sum, order) => sum + order.items.reduce((s, item) => s + Number(item.quantity || 0), 0), 0);
  const revenue = orders.reduce((sum, order) => sum + Number(order.total || 0), 0);

  const summary = {
    connected: true,
    updatedAt: new Date().toISOString(),
    orderError,
    productError,
    categoryError,
    totals: {
      orders: orders.length,
      units,
      readyOrders: readyOrders.length,
      readyUnits,
      deliveredOrders: deliveredOrders.length,
      revenue,
      products: products.length,
      collections: collections.length
    },
    productTotals: readyProductTotals,
    readyProductTotals,
    orders: orders.sort(orderNewestFirst),
    readyOrders,
    deliveredOrders,
    products,
    collections,
    categories
  };
  ikasSummaryCache = { expiresAt: Date.now() + Math.max(0, Number(process.env.IKAS_SUMMARY_CACHE_MS || 300000)), value: summary };
  return summary;
}

function ikasDateSortValue(value) {
  if (value === null || value === undefined || value === "") return 0;
  if (typeof value === "number") return value < 10000000000 ? value * 1000 : value;
  const raw = String(value).trim();
  if (!raw) return 0;
  if (/^\d+$/.test(raw)) {
    const num = Number(raw);
    return num < 10000000000 ? num * 1000 : num;
  }
  const parsed = Date.parse(raw);
  return Number.isFinite(parsed) ? parsed : 0;
}

function orderNewestFirst(a, b) {
  const bt = Number(b.orderSort || ikasDateSortValue(b.orderedAt) || b.orderSequence || b.orderNumber || 0);
  const at = Number(a.orderSort || ikasDateSortValue(a.orderedAt) || a.orderSequence || a.orderNumber || 0);
  return bt - at;
}

function normalizeIkasOrders(rawOrders) {
  return rawOrders.map((order) => {
    const customerName =
      valueOrEmpty(order.customer && order.customer.fullName) ||
      [order.customer && order.customer.firstName, order.customer && order.customer.lastName].filter(Boolean).join(" ").trim() ||
      [order.shippingAddress && order.shippingAddress.firstName, order.shippingAddress && order.shippingAddress.lastName].filter(Boolean).join(" ").trim() ||
      "Müşteri";

    const packageStatuses = Array.isArray(order.orderPackages)
      ? order.orderPackages.map((pkg) => String(pkg.orderPackageFulfillStatus || "").trim()).filter(Boolean)
      : [];
    const packageStockLocationIds = Array.isArray(order.orderPackages)
      ? order.orderPackages.map((pkg) => valueOrEmpty(pkg && pkg.stockLocationId)).filter(Boolean)
      : [];

    const items = groupIkasBundleOrderItems(Array.isArray(order.orderLineItems) ? order.orderLineItems.map((item) => normalizeIkasLineItem(item, order)) : []);
    const dateSource = order.orderedAt || order.createdAt || order.updatedAt;

    return {
      id: valueOrEmpty(order.id),
      number: order.orderNumber ? `#${order.orderNumber}` : valueOrEmpty(order.id).slice(0, 8),
      orderNumber: valueOrEmpty(order.orderNumber),
      orderSequence: Number(order.orderSequence || order.orderNumber || 0),
      customer: customerName,
      customerId: valueOrEmpty(order.customer && order.customer.id),
      isGuestCheckout: Boolean(order.customer && order.customer.isGuestCheckout),
      phone: valueOrEmpty(order.customer && order.customer.phone) || valueOrEmpty(order.shippingAddress && order.shippingAddress.phone),
      email: valueOrEmpty(order.customer && order.customer.email),
      city: valueOrEmpty(order.shippingAddress && order.shippingAddress.city && order.shippingAddress.city.name),
      district: valueOrEmpty(order.shippingAddress && order.shippingAddress.district && order.shippingAddress.district.name),
      statusRaw: valueOrEmpty(order.status),
      packageStatusRaw: valueOrEmpty(order.orderPackageStatus) || packageStatuses[0] || "",
      paymentStatusRaw: valueOrEmpty(order.orderPaymentStatus),
      status: translateOrderStatus(order.status, order.orderPackageStatus, order.orderPaymentStatus),
      packageStatus: translatePackageStatus(order.orderPackageStatus || packageStatuses[0] || ""),
      paymentStatus: translatePaymentStatus(order.orderPaymentStatus),
      orderedAt: normalizeIkasDate(dateSource),
      orderSort: ikasDateSortValue(dateSource) || Number(order.orderSequence || order.orderNumber || 0),
      total: Number(order.totalFinalPrice ?? order.totalPrice ?? 0),
      currency: valueOrEmpty(order.currencySymbol) || valueOrEmpty(order.currencyCode) || "₺",
      salesChannelId: valueOrEmpty(order.salesChannelId),
      sourceId: valueOrEmpty(order.sourceId),
      priceListId: valueOrEmpty(order.priceListId),
      stockLocationId: valueOrEmpty(order.stockLocationId) || packageStockLocationIds[0] || "",
      note: valueOrEmpty(order.note),
      orderTagIds: Array.isArray(order.orderTagIds) ? order.orderTagIds.map(valueOrEmpty).filter(Boolean) : [],
      isExchangeOrder: /DEĞİŞİM SİPARİŞİ|Ruth panel değişim siparişi/i.test(valueOrEmpty(order.note)),
      items
    };
  }).sort(orderNewestFirst);
}


function groupIkasBundleOrderItems(items) {
  const list = Array.isArray(items) ? items : [];
  const groups = new Map();
  const result = [];

  list.forEach((item, index) => {
    const key = item && item.bundleLineId ? String(item.bundleLineId) : "";
    if (!key) {
      if (item && Array.isArray(item.bundleProducts) && item.bundleProducts.length) {
        item.isBundle = true;
        item.bundleItems = item.bundleProducts.map((child) => ({
          ...child,
          quantity: Number(child.quantity || 1) * Number(item.quantity || 1)
        }));
      }
      result.push(item);
      return;
    }

    if (!groups.has(key)) {
      const parentName = item.bundleName || item.baseName || item.name || "Paket ürün";
      const parent = {
        ...item,
        id: `${key}::bundle`,
        name: item.bundleVariantText ? `${parentName} — ${item.bundleVariantText}` : parentName,
        baseName: parentName,
        variantId: item.bundleVariantId || item.variantId,
        productId: item.productId,
        sku: item.sku,
        isBundle: true,
        isBundleComponent: false,
        bundleLineId: key,
        bundleItems: [],
        quantity: Math.max(1, Number(item.bundleLineQuantity || item.quantity || 1)),
        totalPrice: 0,
        unitPrice: 0,
        image: item.image || "",
        mainImageId: item.mainImageId || ""
      };
      groups.set(key, parent);
      result.push(parent);
    }

    const parent = groups.get(key);
    const child = {
      ...item,
      isBundle: false,
      isBundleComponent: true,
      parentBundleLineId: key
    };
    parent.bundleItems.push(child);
    parent.totalPrice += Number(item.totalPrice || 0);
    if (!parent.image && item.image) parent.image = item.image;
    if (!parent.mainImageId && item.mainImageId) parent.mainImageId = item.mainImageId;
    parent.status = parent.status || item.status;
  });

  result.forEach((item) => {
    if (item && item.isBundle) {
      item.bundleItems = (item.bundleItems || []).sort((a, b) => String(a.name || "").localeCompare(String(b.name || ""), "tr"));
      item.unitPrice = Number((Number(item.totalPrice || 0) / Math.max(1, Number(item.quantity || 1))).toFixed(2));
      if (!item.totalPrice && item.bundleItems.length) {
        item.totalPrice = item.bundleItems.reduce((sum, child) => sum + Number(child.totalPrice || 0), 0);
        item.unitPrice = Number((Number(item.totalPrice || 0) / Math.max(1, Number(item.quantity || 1))).toFixed(2));
      }
    }
  });

  return result;
}


function normalizeIkasLineItem(item, order) {
  const variant = item && item.variant ? item.variant : {};
  const product = item && item.product ? item.product : {};
  const variantText = buildVariantText(item, variant);
  const name =
    valueOrEmpty(product.name) ||
    valueOrEmpty(item && item.productName) ||
    valueOrEmpty(item && item.productTitle) ||
    valueOrEmpty(item && item.title) ||
    valueOrEmpty(variant.name) ||
    valueOrEmpty(item && item.name) ||
    "Ürün";
  const mainImageId = valueOrEmpty(variant.mainImageId || product.mainImageId || item && item.mainImageId);
  const directImage =
    valueOrEmpty(item && item.imageUrl) ||
    valueOrEmpty(item && item.image) ||
    valueOrEmpty(product.imageUrl) ||
    valueOrEmpty(product.image) ||
    buildIkasImageUrl(mainImageId);
  const bundleSettings = item && item.bundleProductSettings ? item.bundleProductSettings : null;
  const bundleVariant = bundleSettings && bundleSettings.variant ? bundleSettings.variant : {};
  const bundleText = buildVariantText(bundleSettings || {}, bundleVariant);
  const bundleProducts = Array.isArray(variant.bundleProducts)
    ? variant.bundleProducts.map((bp) => {
        const bpVariant = bp && bp.variant ? bp.variant : {};
        const bpName = valueOrEmpty(bp && bp.name) || valueOrEmpty(bpVariant.name) || "Paket içeriği";
        return {
          id: valueOrEmpty(bp && bp.id) || valueOrEmpty(bpVariant.id),
          variantId: valueOrEmpty(bpVariant.id),
          productId: valueOrEmpty(bpVariant.productId),
          name: bpName,
          sku: valueOrEmpty(bpVariant.sku),
          image: buildIkasImageUrl(valueOrEmpty(bpVariant.mainImageId)),
          mainImageId: valueOrEmpty(bpVariant.mainImageId),
          quantity: Number(bp && bp.quantity || 1),
          unitPrice: Number(bp && (bp.finalPrice ?? bp.price) || 0),
          totalPrice: Number(bp && (bp.finalPrice ?? bp.price) || 0)
        };
      }).filter((bp) => bp.name || bp.variantId || bp.productId)
    : [];
  return {
    id: valueOrEmpty(item && item.id) || valueOrEmpty(variant.id),
    variantId: valueOrEmpty(variant.id) || valueOrEmpty(item && item.variantId),
    productId: valueOrEmpty(product.id) || valueOrEmpty(item && item.productId) || valueOrEmpty(variant.productId),
    name: variantText ? `${name} — ${variantText}` : name,
    baseName: name,
    variantText,
    sku: valueOrEmpty(variant.sku) || valueOrEmpty(item && item.sku),
    slug: valueOrEmpty(product.slug) || valueOrEmpty(variant.slug) || valueOrEmpty(item && item.slug),
    image: directImage,
    mainImageId,
    categories: Array.isArray(variant.categories) ? variant.categories.map((category) => ({ id: valueOrEmpty(category.id), name: valueOrEmpty(category.name) })).filter((category) => category.id || category.name) : [],
    quantity: Number((item && item.quantity) || 0),
    unitPrice: Number((Number((item && (item.finalPrice ?? item.price)) || 0) / Math.max(1, Number((item && item.quantity) || 1))) || 0),
    totalPrice: Number((item && (item.finalPrice ?? item.price)) || 0),
    stockLocationId: valueOrEmpty(item && item.stockLocationId) || valueOrEmpty(order && order.stockLocationId),
    statusRaw: valueOrEmpty(item && item.status),
    status: translateLineStatus(item && item.status),
    orderNumber: order && order.orderNumber ? `#${order.orderNumber}` : "",
    orderId: valueOrEmpty(order && order.id),
    bundleLineId: valueOrEmpty(bundleSettings && bundleSettings.bundleLineId),
    bundleLineQuantity: Number(bundleSettings && bundleSettings.bundleLineQuantity || 0),
    bundleName: valueOrEmpty(bundleSettings && bundleSettings.name) || valueOrEmpty(bundleVariant.name),
    bundleVariantId: valueOrEmpty(bundleVariant.id),
    bundleVariantText: bundleText,
    isBundleComponent: Boolean(bundleSettings && (bundleSettings.bundleLineId || bundleSettings.name || bundleSettings.variant)),
    bundleProducts
  };
}

function buildVariantText(item, variant) {
  const parts = [];

  if (variant && Array.isArray(variant.variantValues)) {
    variant.variantValues.forEach((value) => {
      const left = valueOrEmpty(value.variantTypeName);
      const right = valueOrEmpty(value.variantValueName);
      if (right) parts.push(left ? `${left}: ${right}` : right);
    });
  }

  if (item && Array.isArray(item.options)) {
    item.options.forEach((option) => {
      const name = valueOrEmpty(option.name);
      const values = Array.isArray(option.values)
        ? option.values.map((v) => valueOrEmpty(v.name) || valueOrEmpty(v.value)).filter(Boolean)
        : [];
      if (values.length) parts.push(name ? `${name}: ${values.join(", ")}` : values.join(", "));
    });
  }

  return [...new Set(parts)].join(" / ");
}

function buildIkasImageUrl(mainImageId) {
  const id = valueOrEmpty(mainImageId);
  if (!id) return "";
  if (/^https?:\/\//i.test(id)) return id;
  const base = String(process.env.IKAS_IMAGE_BASE_URL || "").trim().replace(/\/+$/, "");
  if (base) return `${base}/${encodeURIComponent(id)}`;
  return "";
}




