function getManualRuthProductUrlOverride(item) {
  const keys = [];
  [item && item.name, item && item.baseName].forEach((value) => {
    const raw = String(value || '').trim();
    if (!raw) return;
    keys.push(raw.toLowerCase());
    keys.push(normalizeLookupText(raw));
    keys.push(normalizeSlug(raw));
  });
  [item && item.slug, item && item.productSlug, item && item.handle].forEach((value) => {
    const raw = String(value || '').trim();
    if (!raw) return;
    keys.push(raw.toLowerCase());
    keys.push(normalizeSlug(raw));
  });
  for (const key of keys) {
    if (key && RUTH_MANUAL_PRODUCT_URL_OVERRIDES.has(key)) return RUTH_MANUAL_PRODUCT_URL_OVERRIDES.get(key);
  }
  return '';
}

function getMappedRuthProductSlugs(slugs) {
  const mappedPriority = [];
  const existing = [...slugs];
  existing.forEach((slug) => {
    const key = normalizeSlug(slug);
    const mapped = RUTH_PRODUCT_SLUG_MAP.get(key);
    if (mapped) mapped.forEach((value) => mappedPriority.push(value));
  });
  return mappedPriority;
}

function addMappedRuthProductSlugs(slugs) {
  getMappedRuthProductSlugs(slugs).forEach((value) => slugs.push(value));
}


async function enrichIkasImagesDirectFromProductPages(orders, products, categories) {
  if (!IKAS_FETCH_STOREFRONT_IMAGES || !IKAS_STOREFRONT_URL) return;
  const targets = [];
  const pushTarget = (kind, item, setter) => {
    if (!item || item.image) return;
    const candidates = buildStorefrontProductUrlCandidates(item);
    if (!candidates.length) return;
    targets.push({ kind, item, setter, candidates });
  };

  (products || []).forEach((product) => {
    pushTarget("product", product, (image) => { product.image = image; });
    (product.variants || []).forEach((variant) => {
      pushTarget("variant", { ...variant, name: product.name, baseName: product.name, productSlug: product.slug }, (image) => {
        variant.image = image;
        if (!product.image) product.image = image;
      });
    });
  });

  (orders || []).forEach((order) => {
    (order.items || []).forEach((item) => {
      pushTarget("orderItem", item, (image) => { item.image = image; });
    });
  });

  if (!targets.length) return;
  const limit = Math.max(1, Math.min(220, Number(process.env.IKAS_DIRECT_IMAGE_LIMIT || 220)));
  const limited = targets.slice(0, limit);
  const concurrency = Math.max(1, Math.min(3, Number(process.env.IKAS_DIRECT_IMAGE_CONCURRENCY || 2)));
  let index = 0;
  let found = 0;

  async function worker() {
    while (index < limited.length) {
      const target = limited[index++];
      try {
        for (const url of target.candidates) {
          const info = await fetchStorefrontProductImage(url);
          if (info && info.image) {
            target.setter(info.image);
            found += 1;
            break;
          }
        }
      } catch (error) {}
    }
  }

  await Promise.all(Array.from({ length: concurrency }, worker));

  // Sipariş satırındaki görseli aynı SKU/ürün adına sahip ürün kartlarına da yay.
  const byName = new Map();
  const bySku = new Map();
  (orders || []).forEach((order) => {
    (order.items || []).forEach((item) => {
      if (!item || !item.image) return;
      if (item.sku) bySku.set(String(item.sku).toLowerCase(), item.image);
      const key = normalizeLookupText(item.baseName || item.name);
      if (key) byName.set(key, item.image);
    });
  });
  (products || []).forEach((product) => {
    if (!product.image) {
      const key = normalizeLookupText(product.name);
      const img = key ? byName.get(key) : "";
      if (img) product.image = img;
    }
    (product.variants || []).forEach((variant) => {
      if (!variant.image && variant.sku && bySku.has(String(variant.sku).toLowerCase())) variant.image = bySku.get(String(variant.sku).toLowerCase());
      if (!product.image && variant.image) product.image = variant.image;
    });
  });

  if (found && String(process.env.IKAS_IMAGE_DEBUG_LOGS || "0") === "1") console.log(`Ikas direct storefront images matched: ${found}`);
}

function buildStorefrontProductUrlCandidates(item) {
  const manualOverride = getManualRuthProductUrlOverride(item);
  if (manualOverride === "__UNPUBLISHED__") return [];
  const slugs = [];
  const pushSlug = (value) => {
    const raw = String(value || "").trim();
    if (!raw) return;
    if (/^https?:\/\//i.test(raw)) {
      slugs.push(raw);
      return;
    }
    const clean = normalizeSlug(raw.replace(/^\/+|\/+$/g, ""));
    if (clean) slugs.push(clean);
  };

  pushSlug(item.slug);
  pushSlug(item.productSlug);
  pushSlug(item.handle);

  const names = [item.baseName, item.name].filter(Boolean);
  names.forEach((name) => {
    const original = String(name || "").replace(/—.*$/g, "").replace(/\s+-\s+.*$/g, "").trim();
    const variants = new Set();

    const addNameVariant = (value) => {
      const raw = String(value || "").trim();
      if (!raw) return;
      variants.add(raw);
      variants.add(raw.replace(/\([^)]*\)/g, " ").trim());
      variants.add(raw.replace(/ayarlanabilir/gi, " ").trim());
      variants.add(raw.replace(/\([^)]*\)/g, " ").replace(/ayarlanabilir/gi, " ").trim());
      variants.add(raw.replace(/[’'`´]/g, ""));
    };

    addNameVariant(original);
    variants.forEach((base) => {
      if (!base) return;
      pushSlug(base);
      const withoutThe = base.replace(/^the\s+/i, "");
      if (withoutThe !== base) pushSlug(withoutThe);
      if (/ring|necklace|bracelet|set|kolye|yüzük|yuzuk|bileklik/i.test(base)) {
        pushSlug(`${base} brass`);
        if (withoutThe !== base) pushSlug(`${withoutThe} brass`);
      }
    });
  });

  const mappedPriority = getMappedRuthProductSlugs(slugs);
  const unique = [...new Set([...mappedPriority, ...slugs])].slice(0, 36);
  const urls = [];
  if (manualOverride && /^https?:\/\//i.test(manualOverride)) urls.push(manualOverride);
  unique.forEach((slug) => {
    if (/^https?:\/\//i.test(slug)) {
      urls.push(slug);
      return;
    }
    [
      `/${slug}`,
      `/products/${slug}`,
      `/product/${slug}`,
      `/urun/${slug}`,
      `/p/${slug}`
    ].forEach((path) => urls.push(new URL(path, IKAS_STOREFRONT_URL).toString()));
  });
  return [...new Set(urls)].slice(0, 80);
}

async function enrichIkasImagesFromStorefront(orders, products, categories) {
  if (!IKAS_FETCH_STOREFRONT_IMAGES || !IKAS_STOREFRONT_URL) return;
  let imageMap = null;
  try {
    imageMap = await getStorefrontImageMap(products);
  } catch (error) {
    console.error("storefront image map error:", error && error.message ? error.message : error);
    return;
  }
  if (!imageMap || (!imageMap.bySlug.size && !imageMap.byName.size)) return;

  const resolve = (item) => {
    if (!item || item.image) return item && item.image || "";
    const candidates = [];
    [item.slug, item.productSlug, item.handle].forEach((value) => { if (value) candidates.push(String(value)); });
    [item.name, item.baseName].forEach((value) => { if (value) candidates.push(slugifyForUrl(value)); });
    for (const candidate of candidates) {
      const key = normalizeSlug(candidate);
      if (key && imageMap.bySlug.has(key)) return imageMap.bySlug.get(key).image || "";
    }
    const nameKeys = [item.baseName, item.name].map(normalizeLookupText).filter(Boolean);
    for (const key of nameKeys) {
      if (imageMap.byName.has(key)) return imageMap.byName.get(key).image || "";
      const noThe = key.replace(/^the-/, "");
      if (noThe && imageMap.byName.has(noThe)) return imageMap.byName.get(noThe).image || "";
    }
    return "";
  };

  (orders || []).forEach((order) => {
    (order.items || []).forEach((item) => {
      const image = resolve(item);
      if (image) item.image = image;
    });
  });

  (products || []).forEach((product) => {
    const image = resolve(product);
    if (image) product.image = image;
    (product.variants || []).forEach((variant) => {
      const variantImage = resolve({ ...variant, name: product.name, baseName: product.name, productSlug: product.slug });
      if (variantImage) variant.image = variantImage;
    });
    if (!product.image) product.image = (product.variants || []).find((variant) => variant.image)?.image || "";
  });

  (categories || []).forEach((category) => {
    if (category.image) return;
    const key = normalizeLookupText(category.name);
    if (key && imageMap.byName.has(key)) category.image = imageMap.byName.get(key).image || "";
  });
}


function extractImageUrlFromImgTag(tag, baseUrl) {
  const html = String(tag || "");
  const srcset = pickAttr(html, "srcset") || pickAttr(html, "data-srcset");
  if (srcset) {
    const first = srcset.split(",").map((part) => part.trim().split(/\s+/)[0]).filter(Boolean)[0];
    if (first) return absolutizeUrl(first, baseUrl);
  }
  const raw =
    pickAttr(html, "src") ||
    pickAttr(html, "data-src") ||
    pickAttr(html, "data-original") ||
    pickAttr(html, "data-lazy") ||
    pickAttr(html, "data-url") ||
    "";
  return absolutizeUrl(raw, baseUrl);
}

function pickAttr(html, attr) {
  const pattern = new RegExp(attr + "\\\\s*=\\\\s*[\\\"']([^\\\"']+)[\\\"']", "i");
  const match = String(html || "").match(pattern);
  return match ? decodeHtmlEntity(match[1]) : "";
}

function stripTags(value) {
  return decodeHtmlEntity(String(value || "").replace(/<script[\s\S]*?<\/script>/gi, " ").replace(/<style[\s\S]*?<\/style>/gi, " ").replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim());
}

function findBestProductNameNearImage(cleanText, knownProductNames) {
  const text = normalizeLookupText(cleanText);
  if (!text) return "";
  let best = "";
  let bestLen = 0;
  (knownProductNames || []).forEach((name) => {
    const key = normalizeLookupText(name);
    if (!key || key.length < 3) return;
    if (text.includes(key) && key.length > bestLen) {
      best = name;
      bestLen = key.length;
      return;
    }
    const noThe = key.replace(/^the-/, "");
    if (noThe && noThe.length > 3 && text.includes(noThe) && noThe.length > bestLen) {
      best = name;
      bestLen = noThe.length;
    }
  });
  return best;
}

function extractProductImagesFromListingHtml(html, baseUrl, knownProductNames = []) {
  const results = [];
  const source = String(html || "");
  const imgRe = /<img\b[^>]*>/gi;
  let match;
  while ((match = imgRe.exec(source))) {
    const tag = match[0];
    const image = extractImageUrlFromImgTag(tag, baseUrl);
    if (!image || !/^https?:\/\//i.test(image)) continue;
    if (!/cdn\.myikas\.com|images|uploads|cdn/i.test(image)) continue;

    const alt = cleanStorefrontTitle(pickAttr(tag, "alt") || pickAttr(tag, "title") || "");
    const start = Math.max(0, match.index - 1400);
    const end = Math.min(source.length, match.index + tag.length + 1800);
    const nearbyText = stripTags(source.slice(start, end));

    let title = alt && normalizeLookupText(alt).length > 2 ? alt : "";
    if (!title) title = findBestProductNameNearImage(nearbyText, knownProductNames);
    if (!title) continue;

    results.push({
      url: baseUrl,
      slug: slugifyForUrl(title),
      title,
      image
    });
  }
  return results;
}

async function enrichStorefrontImageMapFromListingPages(bySlug, byName, products = []) {
  if (!IKAS_STOREFRONT_URL) return;
  const knownNames = (products || []).map((p) => p && p.name).filter(Boolean);
  const pagePaths = [
    "/",
    "/all-products",
    "/search",
    "/rings",
    "/pendants",
    "/necklaces",
    "/bracelets",
    "/sets",
    "/collections",
    "/shop",
    "/all",
    "/ruth-atelier",
    "/nazar",
    "/sun-kissed",
    "/arya",
    "/huna",
    "/bags"
  ];

  const pages = [...new Set(pagePaths.map((pathName) => new URL(pathName, IKAS_STOREFRONT_URL).toString()))];
  let found = 0;
  for (const pageUrl of pages) {
    try {
      const html = await fetchText(pageUrl);
      const items = extractProductImagesFromListingHtml(html, pageUrl, knownNames);
      items.forEach((info) => {
        if (!info || !info.image) return;
        const slugKey = normalizeSlug(info.slug || info.title);
        const nameKey = normalizeLookupText(info.title);
        if (slugKey && !bySlug.has(slugKey)) bySlug.set(slugKey, info);
        if (nameKey && !byName.has(nameKey)) byName.set(nameKey, info);
        found += 1;
      });
    } catch (error) {}
  }
  if (found && String(process.env.IKAS_IMAGE_DEBUG_LOGS || "0") === "1") console.log(`Ikas listing images matched: ${found}`);
}


async function getStorefrontImageMap(products = []) {
  const now = Date.now();
  if (storefrontImageCache.expiresAt > now) return storefrontImageCache;
  const bySlug = new Map();
  const byName = new Map();
  const urls = await discoverStorefrontProductUrls();
  const limited = urls.slice(0, Number(process.env.IKAS_STOREFRONT_IMAGE_LIMIT || 220));
  const concurrency = Math.max(1, Math.min(3, Number(process.env.IKAS_STOREFRONT_IMAGE_CONCURRENCY || 2)));
  let index = 0;
  async function worker() {
    while (index < limited.length) {
      const url = limited[index++];
      try {
        const info = await fetchStorefrontProductImage(url);
        if (!info || !info.image) continue;
        if (info.slug) bySlug.set(normalizeSlug(info.slug), info);
        if (info.title) byName.set(normalizeLookupText(info.title), info);
      } catch (error) {}
    }
  }
  await Promise.all(Array.from({ length: concurrency }, worker));
  await enrichStorefrontImageMapFromListingPages(bySlug, byName, products);
  storefrontImageCache = { expiresAt: now + 30 * 60 * 1000, bySlug, byName, urls: limited };
  return storefrontImageCache;
}

async function discoverStorefrontProductUrls() {
  const sitemapUrls = [new URL("/sitemap.xml", IKAS_STOREFRONT_URL).toString()];
  const seenSitemaps = new Set();
  const productUrls = new Set();

  for (let i = 0; i < sitemapUrls.length && i < 20; i += 1) {
    const sitemapUrl = sitemapUrls[i];
    if (seenSitemaps.has(sitemapUrl)) continue;
    seenSitemaps.add(sitemapUrl);
    let xml = "";
    try { xml = await fetchText(sitemapUrl); } catch (error) { continue; }
    const locs = [...xml.matchAll(/<loc>\s*([^<]+?)\s*<\/loc>/gi)].map((m) => decodeHtmlEntity(m[1].trim()));
    locs.forEach((loc) => {
      if (/\.xml(\?|$)/i.test(loc) && sitemapUrls.length < 20) sitemapUrls.push(loc);
      else if (isLikelyProductUrl(loc)) productUrls.add(stripQueryHash(loc));
    });
  }

  // Sitemap boşsa veya ürün vermiyorsa ana sayfa + koleksiyon sayfalarını tara.
  const seedPaths = [
    "/",
    "/all-products",
    "/search",
    "/rings",
    "/pendants",
    "/necklaces",
    "/bracelets",
    "/sets",
    "/collections",
    "/shop",
    "/all",
    "/ruth-atelier",
    "/nazar",
    "/sun-kissed",
    "/arya",
    "/huna",
    "/bags"
  ];

  for (const pathName of seedPaths) {
    try {
      const url = new URL(pathName, IKAS_STOREFRONT_URL).toString();
      const html = await fetchText(url);
      extractProductUrlsFromHtml(html, url).forEach((url) => productUrls.add(url));
    } catch (error) {}
  }

  return [...productUrls];
}

function isLikelyProductUrl(url) {
  const text = String(url || "");
  if (/\/(products|product|urun|ürün|p)\//i.test(text)) return true;
  try {
    const u = new URL(text);
    const parts = u.pathname.split("/").filter(Boolean);
    if (parts.length === 1 && /ring|necklace|bracelet|set|kolye|yuzuk|yüzük|bileklik|earring|kupe|küpe|golden|nazar|sacred|ancient|gaze|leaf|temple|glyph|oracle|archive/i.test(parts[0])) return true;
  } catch (error) {}
  return false;
}

function extractProductUrlsFromHtml(html, baseUrl) {
  const urls = new Set();
  const re = /href=["']([^"']+)["']/gi;
  let match;
  while ((match = re.exec(String(html || "")))) {
    try {
      const absolute = new URL(match[1], baseUrl).toString();
      if (isLikelyProductUrl(absolute)) urls.add(stripQueryHash(absolute));
    } catch (error) {}
  }
  return [...urls];
}

async function fetchStorefrontProductImage(url) {
  const html = await fetchText(url);
  const image = absolutizeUrl(
    pickMeta(html, "og:image") ||
    pickMeta(html, "twitter:image") ||
    pickJsonLdImage(html) ||
    "",
    url
  );
  const title = cleanStorefrontTitle(
    pickMeta(html, "og:title") ||
    pickMeta(html, "twitter:title") ||
    pickTitle(html) ||
    ""
  );
  const slug = getSlugFromUrl(url);
  return { url, slug, title, image };
}

async function fetchText(url) {
  const timeoutMs = Math.max(2500, Math.min(12000, Number(process.env.IKAS_STOREFRONT_FETCH_TIMEOUT_MS || 4500)));
  const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
  const timer = controller ? setTimeout(() => controller.abort(), timeoutMs) : null;
  try {
    const response = await fetch(url, {
      signal: controller ? controller.signal : undefined,
      headers: {
        "User-Agent": "Mozilla/5.0 RuthIstanbulPanel/1.0",
        "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8"
      }
    });
    if (!response.ok) throw new Error(`fetch ${response.status} ${url}`);
    return await response.text();
  } finally {
    if (timer) clearTimeout(timer);
  }
}

function pickMeta(html, property) {
  const safe = property.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const patterns = [
    new RegExp(`<meta[^>]+(?:property|name)=["']${safe}["'][^>]+content=["']([^"']+)["'][^>]*>`, "i"),
    new RegExp(`<meta[^>]+content=["']([^"']+)["'][^>]+(?:property|name)=["']${safe}["'][^>]*>`, "i")
  ];
  for (const pattern of patterns) {
    const match = String(html || "").match(pattern);
    if (match && match[1]) return decodeHtmlEntity(match[1]);
  }
  return "";
}

function pickTitle(html) {
  const match = String(html || "").match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return match ? decodeHtmlEntity(match[1].replace(/\s+/g, " ").trim()) : "";
}

function pickJsonLdImage(html) {
  const scripts = [...String(html || "").matchAll(/<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi)];
  for (const script of scripts) {
    try {
      const data = JSON.parse(script[1].trim());
      const found = findImageInJsonLd(data);
      if (found) return found;
    } catch (error) {}
  }
  return "";
}

function findImageInJsonLd(value) {
  if (!value) return "";
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = findImageInJsonLd(item);
      if (found) return found;
    }
  }
  if (typeof value === "object") {
    if (value["@type"] && String(value["@type"]).toLowerCase().includes("product") && value.image) {
      if (Array.isArray(value.image)) return String(value.image[0] || "");
      if (typeof value.image === "object") return String(value.image.url || value.image.contentUrl || "");
      return String(value.image || "");
    }
    for (const key of Object.keys(value)) {
      const found = findImageInJsonLd(value[key]);
      if (found) return found;
    }
  }
  return "";
}

function cleanStorefrontTitle(title) {
  return String(title || "").replace(/\s*[|•-]\s*RUTH\s*ISTANBUL.*$/i, "").replace(/\s*[|•-]\s*Ruth.*$/i, "").trim();
}

function absolutizeUrl(url, baseUrl) {
  const raw = String(url || "").trim();
  if (!raw) return "";
  try { return new URL(raw, baseUrl).toString(); } catch (error) { return raw; }
}

function stripQueryHash(url) {
  try { const u = new URL(url); u.hash = ""; u.search = ""; return u.toString(); } catch (error) { return String(url || ""); }
}

function getSlugFromUrl(url) {
  try {
    const parts = new URL(url).pathname.split("/").filter(Boolean);
    return parts[parts.length - 1] || "";
  } catch (error) {
    return "";
  }
}

function normalizeSlug(value) {
  return slugifyForUrl(String(value || "").replace(/^\/+|\/+$/g, ""));
}

function slugifyForUrl(value) {
  return String(value || "")
    .replace(/\([^)]*\)/g, " ")
    .replace(/ayarlanabilir/gi, " ")
    .replace(/[’'`´]/g, "")
    .replace(/æ/gi, "ae")
    .replace(/œ/gi, "oe")
    .replace(/þ/gi, "th")
    .replace(/ð/gi, "d")
    .toLocaleLowerCase("tr")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ğ/g, "g").replace(/ü/g, "u").replace(/ş/g, "s").replace(/ı/g, "i").replace(/ö/g, "o").replace(/ç/g, "c")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function normalizeLookupText(value) {
  return slugifyForUrl(String(value || "").replace(/—.*$/g, "").replace(/\s+-\s+.*$/g, ""));
}

function normalizeStorefrontUrl(value) {
  const raw = String(value || "").trim().replace(/\/+$/, "");
  if (!raw) return "";
  if (/^https?:\/\//i.test(raw)) return raw;
  return `https://${raw}`;
}

function decodeHtmlEntity(value) {
  return String(value || "")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">");
}

function buildReadyProductTotals(readyOrders) {
  const map = new Map();

  function addReadyItem(order, item, multiplier = 1, parentName = "") {
    const qty = Number(item.quantity || 0) * Number(multiplier || 1);
    const key = item.variantId || item.sku || item.name;
    const existing = map.get(key) || {
      key,
      name: item.name,
      baseName: item.baseName || item.name,
      variantText: item.variantText || "",
      sku: item.sku || "",
      image: item.image || "",
      mainImageId: item.mainImageId || "",
      quantity: 0,
      orders: [],
      fromBundle: parentName || ""
    };
    existing.quantity += qty;
    existing.orders.push({ orderNumber: order.number, quantity: qty, customer: order.customer, bundle: parentName || "" });
    if (!existing.image && item.image) existing.image = item.image;
    if (!existing.fromBundle && parentName) existing.fromBundle = parentName;
    map.set(key, existing);
  }

  readyOrders.forEach((order) => {
    order.items.forEach((item) => {
      const bundleItems = Array.isArray(item.bundleItems) ? item.bundleItems : [];
      if ((item.isBundle || bundleItems.length) && bundleItems.length) {
        bundleItems.forEach((child) => addReadyItem(order, child, 1, item.name || "Paket ürün"));
      } else {
        addReadyItem(order, item, 1, "");
      }
    });
  });

  return [...map.values()].sort((a, b) => Number(b.quantity || 0) - Number(a.quantity || 0));
}

function isReadyOrder(order) {
  const values = [
    order && order.packageStatusRaw,
    order && order.statusRaw,
    ...(order && order.items ? order.items.map((item) => item.statusRaw) : [])
  ].map((value) => String(value || "").toUpperCase());

  return values.some((value) =>
    value.includes("READY_FOR_SHIPMENT") ||
    value.includes("READY_TO_SHIP") ||
    value.includes("READY")
  );
}

function isDeliveredOrder(order) {
  const values = [
    order && order.packageStatusRaw,
    order && order.statusRaw,
    ...(order && order.items ? order.items.map((item) => item.statusRaw) : [])
  ].map((value) => String(value || "").toUpperCase());

  return values.some((value) =>
    value.includes("DELIVERED") ||
    value.includes("FULFILLED") ||
    value.includes("COMPLETED")
  );
}

function translateOrderStatus(status, packageStatus, paymentStatus) {
  const packageText = translatePackageStatus(packageStatus);
  const raw = String(status || "").toUpperCase();
  if (packageText && packageText !== "Durum Yok") return packageText;
  if (!raw) return translatePaymentStatus(paymentStatus) || "Yeni";
  if (raw.includes("CANCEL")) return "İptal Edildi";
  if (raw.includes("REFUND")) return "İade Edildi";
  if (raw.includes("FULFILLED") || raw.includes("DELIVERED") || raw.includes("COMPLETED")) return "Teslim Edildi";
  if (raw.includes("READY")) return "Kargoya Hazır";
  if (raw.includes("OPEN") || raw.includes("CREATED")) return "Yeni";
  return humanizeEnum(raw);
}

function translatePackageStatus(status) {
  const raw = String(status || "").toUpperCase();
  if (!raw) return "Durum Yok";
  if (raw.includes("READY_FOR_SHIPMENT") || raw.includes("READY_TO_SHIP") || raw.includes("READY")) return "Kargoya Hazır";
  if (raw.includes("FULFILLED") || raw.includes("DELIVERED") || raw.includes("COMPLETED")) return "Teslim Edildi";
  if (raw.includes("CANCEL")) return "İptal Edildi";
  if (raw.includes("REFUND")) return "İade Edildi";
  if (raw.includes("UNFULFILLED")) return "Hazırlanıyor";
  return humanizeEnum(raw);
}

function translatePaymentStatus(status) {
  const raw = String(status || "").toUpperCase();
  if (!raw) return "";
  if (raw.includes("PAID")) return "Ödendi";
  if (raw.includes("PENDING")) return "Ödeme Bekliyor";
  if (raw.includes("REFUND")) return "İade Edildi";
  if (raw.includes("CANCEL")) return "İptal Edildi";
  return humanizeEnum(raw);
}

function translateLineStatus(status) {
  const raw = String(status || "").toUpperCase();
  if (!raw) return "";
  if (raw.includes("READY")) return "Kargoya Hazır";
  if (raw.includes("FULFILLED") || raw.includes("DELIVERED") || raw.includes("COMPLETED")) return "Teslim Edildi";
  if (raw.includes("CANCEL")) return "İptal Edildi";
  if (raw.includes("REFUND")) return "İade Edildi";
  return humanizeEnum(raw);
}

function humanizeEnum(value) {
  return String(value || "")
    .toLowerCase()
    .split("_")
    .filter(Boolean)
    .map((part) => part.charAt(0).toLocaleUpperCase("tr") + part.slice(1))
    .join(" ");
}

function valueOrEmpty(value) {
  return value === null || value === undefined ? "" : String(value).trim();
}

function normalizeIkasDate(value) {
  const ms = ikasDateSortValue(value);
  if (!ms) return "";
  const date = new Date(ms);
  if (Number.isNaN(date.getTime())) return "";
  return date.toISOString();
}

function setAdminTyping(conversationId, typing) {
  if (!conversationId) return;
  if (typing) {
    adminTypingState.set(String(conversationId), { typing: true, updatedAt: Date.now() });
  } else {
    adminTypingState.delete(String(conversationId));
  }
}

function isAdminTyping(conversationId) {
  const state = adminTypingState.get(String(conversationId));
  if (!state) return false;
  if (Date.now() - Number(state.updatedAt || 0) > 7000) {
    adminTypingState.delete(String(conversationId));
    return false;
  }
  return true;
}

async function notifyAdmins(payload) {
  if (!webPush || !VAPID_PUBLIC_KEY || !VAPID_PRIVATE_KEY) {
    console.error("Push not configured: web-push/VAPID env missing");
    return false;
  }

  const subscriptions = await storage.listPushSubscriptions();
  if (!subscriptions.length) {
    console.error("Push skipped: no admin device subscription");
    return false;
  }
  await Promise.all(subscriptions.map(async (subscription) => {
    try {
      await webPush.sendNotification({
        endpoint: subscription.endpoint,
        keys: subscription.keys || {}
      }, JSON.stringify(payload), { TTL: 60 * 60 * 24 });
    } catch (error) {
      const status = error && (error.statusCode || error.status);
      if (status === 404 || status === 410) {
        await storage.removePushSubscription(subscription.endpoint);
      } else {
        console.error("Push send failed:", error && error.message ? error.message : error);
      }
    }
  }));
  return true;
}

async function checkDueReminders() {
  const nowIso = new Date().toISOString();
  const due = await storage.listDueReminders(nowIso);
  for (const note of due) {
    const conversation = await storage.getConversation(note.conversationId);
    if (!conversation) continue;
    const sent = await notifyAdmins({
      title: "RUTH CRM Hatırlatma",
      body: `${displayName(conversation)}: ${note.body}`,
      url: `/admin/?conversation=${encodeURIComponent(conversation.id)}&note=${encodeURIComponent(note.id)}`,
      tag: `reminder-${note.id}`,
      data: { conversationId: conversation.id, noteId: note.id }
    });
    if (sent) {
      await storage.updateNote(note.id, {
        reminderSentAt: nowIso,
        updatedAt: nowIso
      });
    }
  }

  const exchangeDue = listDueExchangeReminders(nowIso);
  for (const exchange of exchangeDue) {
    const sent = await notifyAdmins({
      title: "RUTH Değişim Hatırlatma",
      body: `${exchange.customerName || "Müşteri"} • ${exchange.orderDisplay || exchange.orderNumber || "Sipariş"} değişimi`,
      url: `/admin/exchange?order=${encodeURIComponent(exchange.orderId || "")}`,
      tag: `exchange-${exchange.id}`,
      data: { exchangeId: exchange.id, orderId: exchange.orderId, url: `/admin/exchange?order=${encodeURIComponent(exchange.orderId || "")}` }
    });
    if (sent) updateExchangeRecord(exchange.id, { reminderSentAt: nowIso });
  }
}

class FileStore {
  constructor(filePath) {
    this.kind = "file";
    this.filePath = filePath;
    this.db = this.load();
  }

  load() {
    try {
      const raw = fs.readFileSync(this.filePath, "utf8");
      return normalizeDb(JSON.parse(raw));
    } catch (error) {
      return normalizeDb({});
    }
  }

  save() {
    const tempPath = `${this.filePath}.tmp`;
    fs.writeFileSync(tempPath, JSON.stringify(this.db, null, 2), "utf8");
    fs.renameSync(tempPath, this.filePath);
  }

  async nextVisitorLabel(sessionId) {
    this.db.counters.visitor += 1;
    this.save();
    return `Ziyaretçi ${this.db.counters.visitor}`;
  }

  async getConversationBySessionId(sessionId) {
    return this.db.conversations.find((item) => item.sessionId === sessionId) || null;
  }

  async getConversation(id) {
    return this.db.conversations.find((item) => item.id === id) || null;
  }

  async createConversation(data) {
    const item = { id: crypto.randomUUID(), ...data };
    this.db.conversations.push(item);
    this.save();
    return item;
  }

  async updateConversation(id, patch) {
    const item = await this.getConversation(id);
    if (!item) return null;
    Object.assign(item, patch);
    this.save();
    return item;
  }

  async listConversations() {
    return [...this.db.conversations]
      .filter((item) => item.sessionId !== PANEL_RECORD_SESSION_ID)
      .sort((a, b) => String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")));
  }

  async addMessage(data) {
    const item = { id: crypto.randomUUID(), ...data };
    this.db.messages.push(item);
    this.save();
    return item;
  }

  async listMessages(conversationId, after = "") {
    return this.db.messages
      .filter((item) => item.conversationId === conversationId)
      .filter((item) => !after || String(item.createdAt) > after)
      .sort((a, b) => String(a.createdAt).localeCompare(String(b.createdAt)));
  }

  async savePushSubscription(data) {
    this.db.pushSubscriptions = this.db.pushSubscriptions.filter((item) => item.endpoint !== data.endpoint);
    this.db.pushSubscriptions.push(data);
    this.save();
  }

  async listPushSubscriptions() {
    return [...this.db.pushSubscriptions];
  }

  async removePushSubscription(endpoint) {
    this.db.pushSubscriptions = this.db.pushSubscriptions.filter((item) => item.endpoint !== endpoint);
    this.save();
  }

  async addNote(data) {
    const item = { id: crypto.randomUUID(), ...data };
    this.db.customerNotes.push(item);
    this.save();
    return item;
  }

  async listNotes(conversationId) {
    return this.db.customerNotes
      .filter((item) => item.conversationId === conversationId)
      .sort((a, b) => String(b.createdAt || "").localeCompare(String(a.createdAt || "")));
  }

  async updateNote(id, patch) {
    const item = this.db.customerNotes.find((note) => note.id === id);
    if (!item) return null;
    Object.assign(item, patch);
    this.save();
    return item;
  }

  async listDueReminders(nowIso) {
    return this.db.customerNotes.filter((note) =>
      note.reminderAt &&
      !note.reminderSentAt &&
      !note.completedAt &&
      String(note.reminderAt) <= nowIso
    );
  }
}

class SupabaseStore {
  constructor(url, serviceRoleKey) {
    this.kind = "supabase";
    this.url = url;
    this.serviceRoleKey = serviceRoleKey;
  }

  async request(method, resource, body, options = {}) {
    const response = await fetch(`${this.url}/rest/v1/${resource}`, {
      method,
      headers: {
        apikey: this.serviceRoleKey,
        Authorization: `Bearer ${this.serviceRoleKey}`,
        "Content-Type": "application/json",
        Prefer: options.prefer || "return=representation"
      },
      body: body === undefined ? undefined : JSON.stringify(body)
    });

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`supabase_${response.status}: ${text.slice(0, 300)}`);
    }

    if (response.status === 204) return null;
    return response.json();
  }

  async nextVisitorLabel(sessionId) {
    return `Ziyaretçi ${String(sessionId).slice(-6)}`;
  }

  async getConversationBySessionId(sessionId) {
    const rows = await this.request("GET", `conversations?session_id=eq.${encodeURIComponent(sessionId)}&select=*&limit=1`);
    return rows[0] ? fromConversationRow(rows[0]) : null;
  }

  async getConversation(id) {
    const rows = await this.request("GET", `conversations?id=eq.${encodeURIComponent(id)}&select=*&limit=1`);
    return rows[0] ? fromConversationRow(rows[0]) : null;
  }

  async createConversation(data) {
    const rows = await this.request("POST", "conversations", toConversationRow(data));
    return fromConversationRow(rows[0]);
  }

  async updateConversation(id, patch) {
    const rows = await this.request("PATCH", `conversations?id=eq.${encodeURIComponent(id)}`, toConversationRow(patch));
    return rows[0] ? fromConversationRow(rows[0]) : null;
  }

  async listConversations() {
    const rows = await this.request("GET", "conversations?select=*&order=updated_at.desc&limit=300");
    return rows.map(fromConversationRow).filter((item) => item.sessionId !== PANEL_RECORD_SESSION_ID);
  }

  async addMessage(data) {
    const rows = await this.request("POST", "messages", toMessageRow(data));
    return fromMessageRow(rows[0]);
  }

  async listMessages(conversationId, after = "") {
    let query = `messages?conversation_id=eq.${encodeURIComponent(conversationId)}&select=*&order=created_at.asc&limit=500`;
    if (after) query = `messages?conversation_id=eq.${encodeURIComponent(conversationId)}&created_at=gt.${encodeURIComponent(after)}&select=*&order=created_at.asc&limit=500`;
    const rows = await this.request("GET", query);
    return rows.map(fromMessageRow);
  }

  async savePushSubscription(data) {
    await this.request("DELETE", `push_subscriptions?endpoint=eq.${encodeURIComponent(data.endpoint)}`, undefined, { prefer: "return=minimal" });
    await this.request("POST", "push_subscriptions", toPushRow(data));
  }

  async listPushSubscriptions() {
    const rows = await this.request("GET", "push_subscriptions?select=*&limit=200");
    return rows.map(fromPushRow);
  }

  async removePushSubscription(endpoint) {
    await this.request("DELETE", `push_subscriptions?endpoint=eq.${encodeURIComponent(endpoint)}`, undefined, { prefer: "return=minimal" });
  }

  async addNote(data) {
    const rows = await this.request("POST", "customer_notes", toNoteRow(data));
    return fromNoteRow(rows[0]);
  }

  async listNotes(conversationId) {
    const rows = await this.request("GET", `customer_notes?conversation_id=eq.${encodeURIComponent(conversationId)}&select=*&order=created_at.desc&limit=200`);
    return rows.map(fromNoteRow);
  }

  async updateNote(id, patch) {
    const rows = await this.request("PATCH", `customer_notes?id=eq.${encodeURIComponent(id)}`, toNoteRow(patch));
    return rows[0] ? fromNoteRow(rows[0]) : null;
  }

  async listDueReminders(nowIso) {
    const rows = await this.request("GET", `customer_notes?reminder_at=lte.${encodeURIComponent(nowIso)}&reminder_sent_at=is.null&completed_at=is.null&select=*&limit=100`);
    return rows.map(fromNoteRow);
  }
}

function serveStatic(req, res, url) {
  if (req.method !== "GET") return false;

  if (url.pathname === "/ruth-sidebar-wordmark-v134.png") {
    const filePath = path.join(__dirname, "ruth-sidebar-wordmark-v134.png");
    if (fs.existsSync(filePath)) return sendFile(res, filePath);
  }

  if (url.pathname === "/ruth-sidebar-animal-v134.png") {
    const filePath = path.join(__dirname, "ruth-sidebar-animal-v134.png");
    if (fs.existsSync(filePath)) return sendFile(res, filePath);
  }


  if (url.pathname === "/ruth-sidebar-wordmark-v127.png") {
    return sendBinary(res, Buffer.from(RUTH_FULL_LOGO_V91_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/ruth-sidebar-animal-v127.png") {
    return sendBinary(res, Buffer.from(RUTH_ANIMAL_LOGO_V91_BASE64, "base64"), "image/png");
  }


  if (url.pathname === "/ruth-full-logo-v91.png") {
    return sendBinary(res, Buffer.from(RUTH_FULL_LOGO_V91_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/ruth-animal-logo-v91.png") {
    return sendBinary(res, Buffer.from(RUTH_ANIMAL_LOGO_V91_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/ruth-gold-r-logo.png" || url.pathname === "/ruth-favicon-192.png" || url.pathname === "/apple-touch-icon.png" || url.pathname === "/ruth-favicon-180.png") {
    return sendBinary(res, Buffer.from("", "base64"), "image/png");
  }

  if (url.pathname === "/ruth-gold-r-logo.png" || url.pathname === "/ruth-favicon-192.png" || url.pathname === "/apple-touch-icon.png" || url.pathname === "/ruth-favicon-180.png") {
    return sendBinary(res, Buffer.from("", "base64"), "image/png");
  }

  if (url.pathname === "/favicon.ico") {
    return sendBinary(res, Buffer.from(RUTH_FAVICON_ICO_BASE64, "base64"), "image/x-icon");
  }

  if (url.pathname === "/ruth-favicon.png" || url.pathname === "/ruth-favicon-512.png") {
    return sendBinary(res, Buffer.from(RUTH_FAVICON_512_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/ruth-favicon-192.png") {
    return sendBinary(res, Buffer.from(RUTH_FAVICON_192_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/apple-touch-icon.png" || url.pathname === "/ruth-favicon-180.png") {
    return sendBinary(res, Buffer.from(RUTH_FAVICON_180_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/ruth-favicon-32.png") {
    return sendBinary(res, Buffer.from(RUTH_FAVICON_32_BASE64, "base64"), "image/png");
  }

  if (url.pathname === "/admin" || url.pathname === "/admin/") {
    const adminFile = path.join(PUBLIC_DIR, "admin", "index.html");
    if (fs.existsSync(adminFile)) return sendFile(res, adminFile);
    const serverAdmin = verifyToken(readCookie(req, "ruth_admin_token"));
    return sendHtml(res, adminHtml(serverAdmin && isKnownAdmin(serverAdmin.sub) ? serverAdmin : null));
  }

  if (url.pathname.startsWith("/admin/")) {
    const relative = url.pathname.replace(/^\/admin\/+/, "");
    const filePath = path.join(PUBLIC_DIR, "admin", relative);
    if (fs.existsSync(filePath)) return sendFile(res, filePath);
    const serverAdmin = verifyToken(readCookie(req, "ruth_admin_token"));
    return sendHtml(res, adminHtml(serverAdmin && isKnownAdmin(serverAdmin.sub) ? serverAdmin : null));
  }

  if (url.pathname === "/manifest.webmanifest") {
    const manifestFile = path.join(PUBLIC_DIR, "admin", "manifest.webmanifest");
    if (fs.existsSync(manifestFile)) return sendFile(res, manifestFile);
    return sendJson(res, {
      name: "RUTH ISTANBUL Panel",
      short_name: "Ruth Panel",
      start_url: "/admin/",
      scope: "/",
      display: "standalone",
      background_color: "#050505",
      theme_color: "#c79a3a",
      icons: [
        { src: "/ruth-favicon-192.png", sizes: "192x192", type: "image/png" },
        { src: "/ruth-favicon.png", sizes: "512x512", type: "image/png" }
      ]
    });
  }

  if (url.pathname === "/sw.js") {
    const swFile = path.join(PUBLIC_DIR, "admin", "sw.js");
    if (fs.existsSync(swFile)) return sendFile(res, swFile);
    return sendText(res, "self.addEventListener('push',function(event){var data={};try{data=event.data?event.data.json():{};}catch(e){};var target=data.url||(data.data&&data.data.url)||'/admin/';var options={body:data.body||'Yeni müşteri mesajı var.',tag:data.tag||'ruth-message',renotify:true,requireInteraction:true,data:{url:target},icon:data.icon||'/ruth-favicon-192.png',badge:data.badge||'/ruth-favicon-192.png'};event.waitUntil(self.registration.showNotification(data.title||'RUTH ISTANBUL',options));});self.addEventListener('notificationclick',function(event){event.notification.close();var target=(event.notification.data&&event.notification.data.url)||'/admin/';if(!target||target.indexOf('http')===0)target='/admin/';event.waitUntil(clients.matchAll({type:'window',includeUncontrolled:true}).then(function(list){for(var i=0;i<list.length;i++){var client=list[i];if(client.url.indexOf('/admin')>=0&&'focus'in client){client.focus();client.navigate(target);return;}}return clients.openWindow(target);}));});", "text/javascript; charset=utf-8");
  }

  return false;
}

function sendHtml(res, html, status = 200) {
  res.writeHead(status, {
    "Content-Type": "text/html; charset=utf-8",
    "Cache-Control": "no-store"
  });
  res.end(html);
  return true;
}

function sendText(res, value, type = "text/plain; charset=utf-8", status = 200) {
  res.writeHead(status, {
    "Content-Type": type,
    "Cache-Control": "no-store"
  });
  res.end(String(value || ""));
  return true;
}

function sendBinary(res, buffer, type = "application/octet-stream", status = 200) {
  res.writeHead(status, {
    "Content-Type": type,
    "Cache-Control": "public, max-age=31536000, immutable"
  });
  res.end(buffer);
  return true;
}

