  function initPullRefresh(){
    if(window.__ruthPullRefreshReady)return;
    window.__ruthPullRefreshReady=true;
    var startY=0, pulling=false, refreshing=false, ready=false;
    var threshold=96;
    function isMobile(){return window.matchMedia&&window.matchMedia('(max-width:820px)').matches}
    function scrollTop(){return (document.scrollingElement||document.documentElement).scrollTop||window.pageYOffset||0}
    function blockedTarget(t){return t&&t.closest&&t.closest('textarea,input,select,.message-space,.panel-body,.modal,.admin-photo-preview')}
    function setIndicator(y,state){
      var el=$('pullRefresh'), txt=$('pullRefreshText');
      if(!el)return;
      var shown=Math.max(0,Math.min(96,y));
      el.classList.add('visible');
      el.classList.toggle('ready',state==='ready');
      el.classList.toggle('refreshing',state==='refreshing');
      el.classList.toggle('done',state==='done');
      el.style.transform='translate(-50%,'+(-78+shown)+'px)';
      el.style.setProperty('--pull-rotate',Math.round(shown*3.6)+'deg');
      if(txt){
        if(state==='refreshing')txt.textContent='Yenileniyor...';
        else if(state==='done')txt.textContent='Yenilendi';
        else if(state==='ready')txt.textContent='Bırakınca yenilenecek';
        else txt.textContent='Yenilemek için aşağı çek';
      }
    }
    function hideIndicator(){
      var el=$('pullRefresh');
      if(!el)return;
      el.classList.remove('visible','ready','refreshing','done');
      el.style.transform='translate(-50%,-78px)';
      el.style.setProperty('--pull-rotate','0deg');
      var txt=$('pullRefreshText'); if(txt)txt.textContent='Yenilemek için aşağı çek';
    }
    function markReloadDone(){
      try{ sessionStorage.setItem('ruthPullRefreshDone','1'); }catch(_){ }
    }
    function consumeReloadDone(){
      try{
        if(sessionStorage.getItem('ruthPullRefreshDone')==='1'){
          sessionStorage.removeItem('ruthPullRefreshDone');
          setTimeout(function(){
            setIndicator(96,'done');
            setTimeout(function(){hideIndicator(); toast('Sayfa yenilendi');},700);
          },220);
        }
      }catch(_){ }
    }
    consumeReloadDone();
    document.addEventListener('touchstart',function(e){
      if(!isMobile()||refreshing||blockedTarget(e.target))return;
      if(scrollTop()>2)return;
      startY=e.touches&&e.touches[0]?e.touches[0].clientY:0;
      pulling=true; ready=false;
    },{passive:true});
    document.addEventListener('touchmove',function(e){
      if(!pulling||refreshing||!isMobile())return;
      var y=e.touches&&e.touches[0]?e.touches[0].clientY:0;
      var diff=y-startY;
      if(diff<=8)return;
      if(scrollTop()>2){pulling=false;hideIndicator();return;}
      e.preventDefault();
      var shown=Math.min(96,diff*.58);
      ready=shown>=threshold*.58;
      setIndicator(shown,ready?'ready':'pull');
    },{passive:false});
    document.addEventListener('touchend',function(){
      if(!pulling)return;
      pulling=false;
      if(!ready){hideIndicator();return;}
      refreshing=true;
      setIndicator(96,'refreshing');
      markReloadDone();
      var released=false;
      var fallback=setTimeout(function(){
        if(released)return;
        refreshing=false;
        hideIndicator();
        toast('Yenileme tekrar denenebilir');
      },4000);
      window.addEventListener('pagehide',function(){ released=true; clearTimeout(fallback); },{once:true});
      setTimeout(function(){
        try{ window.scrollTo({top:0,behavior:'auto'}); }catch(_){ }
        try{ window.location.reload(); }catch(_){
          clearTimeout(fallback);
          refreshing=false;
          hideIndicator();
          refreshAllData(true).then(function(){toast('Sayfa yenilendi');}).catch(function(){toast('Yenileme başarısız');});
        }
      },140);
    },{passive:true});
    document.addEventListener('touchcancel',function(){
      if(!refreshing){pulling=false;hideIndicator();}
    },{passive:true});
  }

  function loadConversations(silent){ return api('/api/admin/conversations').then(function(d){conversations=d.conversations||[]; renderAll(); if(activeId){ if(activeRoute==='support')loadMessages(activeId,true); if(activeRoute==='crm')loadCrmDetail(activeId,true); }}).catch(function(err){if(!silent)toast(err.message)})}
  function loadReminders(){return api('/api/admin/reminders/due').then(function(d){reminders=d.reminders||[]; renderReminders()}).catch(function(){})}
  function loadExchangeRecords(){return api('/api/admin/exchanges').then(function(d){exchangeRecords=d.exchanges||[]; renderIkas(); renderIkasCustomers(); safeRenderExchange(); renderExchangeNotes(); renderReturnsExchanges();}).catch(function(){exchangeRecords=[]; renderReturnsExchanges();})}
  function loadReturnRecords(){return api('/api/admin/returns').then(function(d){returnRecords=d.returns||[]; renderIkas(); renderReturn(); renderReturnsExchanges();}).catch(function(){returnRecords=[]; renderReturnsExchanges();})}
  function ikasHasVisibleData(s){
    return Boolean(s && (((s.orders||[]).length) || ((s.products||[]).length) || ((s.collections||[]).length) || ((s.readyOrders||[]).length) || ((s.readyProductTotals||[]).length)));
  }
  function isIkasActuallyConnected(s){
    if(!s || !s.connected || s.ikasError)return false;
    if(ikasHasVisibleData(s))return true;
    if(s.orderError && s.productError)return false;
    return false;
  }
  function ikasCurrentStatusText(){
    if(isIkasActuallyConnected(ikasSummary))return 'Bağlandı';
    if(ikasSummary && (ikasSummary.ikasError || (ikasSummary.orderError && ikasSummary.productError)))return 'Bağlanamadı';
    return 'Bağlanıyor';
  }
  function setIkasStatusText(value){
    value=value||'Bağlanıyor';
    ikasStableStatus=value;
    setText('ikasStatus', value);
    setText('topIkasStatusText', value);
    var el=$('ikasStatus');
    if(el){
      el.classList.toggle('ikas-connecting', value==='Bağlanıyor');
      el.classList.toggle('ikas-connected', value==='Bağlandı');
      el.classList.toggle('ikas-failed', value==='Bağlanamadı');
    }
    var top=$('topIkasStatus');
    if(top){
      top.classList.toggle('ikas-connecting', value==='Bağlanıyor');
      top.classList.toggle('ikas-connected', value==='Bağlandı');
      top.classList.toggle('ikas-failed', value==='Bağlanamadı');
    }
  }
  function connectIkasFast(){
    if(isIkasActuallyConnected(ikasSummary)) {
      ikasConnectedFast=true;
      setIkasStatusText('Bağlandı');
      return Promise.resolve(true);
    }
    if(ikasConnecting) return Promise.resolve(false);
    ikasConnecting=true;
    setIkasStatusText('Bağlanıyor');
    return api('/api/admin/ikas/connect').then(function(d){
      if(d && d.connected){
        // Hızlı kontrol geçti ama veri gelmeden Bağlandı yazma.
        if(!isIkasActuallyConnected(ikasSummary)) setIkasStatusText('Bağlanıyor');
        return true;
      }
      if(!isIkasActuallyConnected(ikasSummary)) setIkasStatusText('Bağlanamadı');
      setTimeout(function(){ if(token && !isIkasActuallyConnected(ikasSummary)) connectIkasFast(); }, 3000);
      return false;
    }).catch(function(){
      if(!isIkasActuallyConnected(ikasSummary)) setIkasStatusText('Bağlanamadı');
      setTimeout(function(){ if(token && !isIkasActuallyConnected(ikasSummary)) connectIkasFast(); }, 3000);
      return false;
    }).finally(function(){ikasConnecting=false;});
  }
  function loadIkasSummary(silent,force){
    if(ikasLoading)return Promise.resolve(ikasSummary);
    var wasConnected=isIkasActuallyConnected(ikasSummary);
    ikasLoading=true;

    if(!wasConnected) {
      connectIkasFast();
      setIkasStatusText('Bağlanıyor');
    } else {
      // Bağlıyken arka planda yenileme yap; üst yazıyı Bağlanıyor'a düşürme.
      ikasConnectedFast=true;
      setIkasStatusText('Bağlandı');
    }

    var url='/api/admin/ikas/summary'+(force?'?refresh=1':'?fast=1');
    return api(url).then(function(d){
      if(d && d.connecting && !ikasHasVisibleData(d)){
        if(!wasConnected)setIkasStatusText('Bağlanıyor');
        renderIkas();
        if(token && !wasConnected)setTimeout(function(){loadIkasSummary(true,false)},1000);
        return ikasSummary;
      }

      var previous=ikasSummary;
      ikasSummary=d||ikasSummary;
      ikasConnectedFast=isIkasActuallyConnected(ikasSummary);

      if(ikasConnectedFast){
        setIkasStatusText('Bağlandı');
      } else if(wasConnected && previous){
        // Yeni arka plan cevabı boş/geçici hatalıysa eski bağlı görünümü bozma.
        ikasSummary=previous;
        ikasConnectedFast=true;
        setIkasStatusText('Bağlandı');
      } else {
        setIkasStatusText(ikasCurrentStatusText());
      }

      renderIkas();
      if(!ikasConnectedFast && token && !force)setTimeout(function(){loadIkasSummary(true,false)},1500);
      return ikasSummary;
    }).catch(function(err){
      if(wasConnected){
        // Arka plan yenileme hata verirse panelde zıplama yapma.
        setIkasStatusText('Bağlandı');
      } else {
        ikasSummary.ikasError=err&&err.message?err.message:'ikas bağlantısı kurulamadı';
        ikasConnectedFast=false;
        setIkasStatusText('Bağlanamadı');
        if(token)setTimeout(function(){loadIkasSummary(true,false)},3000);
      }
      if(!silent)toast('ikas bağlantısı yenilenemedi');
      renderIkas();
      return ikasSummary;
    }).finally(function(){
      ikasLoading=false;
      setIkasStatusText(isIkasActuallyConnected(ikasSummary)?'Bağlandı':ikasCurrentStatusText());
    });
  }
