  function clampPage(page,totalPages){page=Number(page||1); if(page<1)page=1; if(totalPages&&page>totalPages)page=totalPages; return page}
  function pagerHtml(target,page,totalPages){if(totalPages<=1)return ''; var prev=Math.max(1,page-1),next=Math.min(totalPages,page+1); var html='<div class="pager"><button data-page-target="'+target+'" data-page="'+prev+'" '+(page<=1?'disabled':'')+'>‹</button>'; var start=Math.max(1,page-2),end=Math.min(totalPages,page+2); if(start>1)html+='<button data-page-target="'+target+'" data-page="1">1</button>'; if(start>2)html+='<span class="time">...</span>'; for(var i=start;i<=end;i++){html+='<button class="'+(i===page?'active':'')+'" data-page-target="'+target+'" data-page="'+i+'">'+i+'</button>'} if(end<totalPages-1)html+='<span class="time">...</span>'; if(end<totalPages)html+='<button data-page-target="'+target+'" data-page="'+totalPages+'">'+totalPages+'</button>'; html+='<button data-page-target="'+target+'" data-page="'+next+'" '+(page>=totalPages?'disabled':'')+'>›</button><span class="time">Sayfa '+page+' / '+totalPages+'</span></div>'; return html}
