function requireAdmin(req, res) {
  const header = String(req.headers.authorization || "");
  const bearerToken = header.startsWith("Bearer ") ? header.slice(7) : "";
  const cookieToken = readCookie(req, "ruth_admin_token");
  const payload = verifyToken(bearerToken) || verifyToken(cookieToken);
  if (!payload || !isKnownAdmin(payload.sub)) {
    sendJson(res, { ok: false, error: "unauthorized" }, 401);
    return null;
  }
  return payload;
}

function signToken(payload) {
  const body = base64url(JSON.stringify(payload));
  const signature = crypto.createHmac("sha256", SESSION_SECRET).update(body).digest("base64url");
  return `${body}.${signature}`;
}

function verifyToken(token) {
  const [body, signature] = String(token || "").split(".");
  if (!body || !signature) return null;
  const expected = crypto.createHmac("sha256", SESSION_SECRET).update(body).digest("base64url");
  if (!safeEqual(signature, expected)) return null;
  try {
    const payload = JSON.parse(Buffer.from(body, "base64url").toString("utf8"));
    if (!payload.exp || payload.exp < Math.floor(Date.now() / 1000)) return null;
    return payload;
  } catch (error) {
    return null;
  }
}

function safeEqual(a, b) {
  const left = Buffer.from(String(a));
  const right = Buffer.from(String(b));
  return left.length === right.length && crypto.timingSafeEqual(left, right);
}

function readCookie(req, name) {
  const raw = String(req.headers.cookie || "");
  const parts = raw.split(/;\s*/);
  for (const part of parts) {
    const index = part.indexOf("=");
    if (index < 0) continue;
    const key = part.slice(0, index);
    const value = part.slice(index + 1);
    if (key === name) {
      try { return decodeURIComponent(value); } catch (error) { return value; }
    }
  }
  return "";
}

function authCookie(token) {
  return `ruth_admin_token=${encodeURIComponent(token)}; Path=/; HttpOnly; SameSite=Lax; Max-Age=${60 * 60 * 24 * 30}`;
}

function clearAuthCookie() {
  return "ruth_admin_token=; Path=/; HttpOnly; SameSite=Lax; Max-Age=0";
}

function readJson(req, limit = 1_000_000) {
  return new Promise((resolve, reject) => {
    let raw = "";
    let failed = false;
    req.on("data", (chunk) => {
      if (failed) return;
      raw += chunk;
      if (raw.length > limit) {
        failed = true;
        const error = new Error("body_too_large");
        error.statusCode = 413;
        reject(error);
        // Bağlantıyı sert kapatma; sert kapatma Render/Node tarafında socket hatası doğurabiliyor.
        req.resume();
      }
    });
    req.on("end", () => {
      if (failed) return;
      try {
        resolve(raw ? JSON.parse(raw) : {});
      } catch (error) {
        reject(error);
      }
    });
    req.on("error", (error) => {
      if (!failed) reject(error);
    });
  });
}


async function getFastIkasImageStatusSummary() {
  if (ikasSummaryCache.value) return ikasSummaryCache.value;

  const timeoutMs = Math.max(1000, Math.min(6000, Number(process.env.IKAS_IMAGE_STATUS_TIMEOUT_MS || 4500)));
  try {
    return await Promise.race([
      buildIkasSummary(),
      new Promise((resolve) => setTimeout(() => resolve({ __busy: true, products: [], orders: [], updatedAt: "" }), timeoutMs))
    ]);
  } catch (error) {
    return { __busy: true, products: [], orders: [], updatedAt: "", error: error && error.message ? error.message : "image_status_error" };
  }
}

function makeImageStatusPayload(summary) {
  const products = summary.products || [];
  const orders = summary.orders || [];
  return {
    ok: true,
    public: true,
    busy: Boolean(summary.__busy),
    products: products.length,
    productsWithImage: products.filter((p) => p.image).length,
    orders: orders.length,
    orderItemsWithImage: orders.reduce((sum, o) => sum + (o.items || []).filter((i) => i.image).length, 0),
    sampleProducts: products.slice(0, 15).map((p) => ({ name: p.name, image: p.image || "" })),
    updatedAt: summary.updatedAt || "",
    note: summary.__busy
      ? "Fotoğraf taraması devam ediyor. 20-30 saniye sonra yenile."
      : "productsWithImage 0'dan büyükse fotoğraflar bulunuyor demektir."
  };
}

function escapeHtmlServer(value) {
  return String(value || "").replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#039;"
  }[char] || char));
}

function sendJson(res, payload, status = 200) {
  if (res.headersSent || res.writableEnded) return true;
  res.writeHead(status, {
    "Content-Type": "application/json; charset=utf-8",
    "Cache-Control": "no-store"
  });
  res.end(JSON.stringify(payload));
  return true;
}

function setCors(res) {
  res.setHeader("Access-Control-Allow-Origin", "*");
  res.setHeader("Access-Control-Allow-Methods", "GET,POST,PATCH,DELETE,OPTIONS");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type, Authorization");
}

function redirect(res, location) {
  res.writeHead(302, { Location: location });
  res.end();
}


