function updateExchangeRecord(id, patch) {
  const db = loadExchangeDb();
  const item = db.exchanges.find((exchange) => exchange.id === id);
  if (!item) return null;
  Object.assign(item, patch, { updatedAt: new Date().toISOString() });
  saveExchangeDb(db);
  return item;
}

function listDueExchangeReminders(nowIso) {
  return listExchangeRecords().filter((exchange) =>
    exchange.reminderAt &&
    !exchange.reminderSentAt &&
    String(exchange.reminderAt) <= nowIso
  );
}

function normalizePanelRecordKind(kind) {
  const raw = String(kind || "").toLowerCase();
  return raw === "return" ? "return" : "exchange";
}

function panelRecordKey(kind, record) {
  const r = record || {};
  return normalizePanelRecordKind(kind) + ":" + String(r.id || r.orderId || r.orderNumber || r.createdAt || crypto.randomUUID());
}

function panelRecordNewer(a, b) {
  const at = String((a && (a.updatedAt || a.createdAt)) || "");
  const bt = String((b && (b.updatedAt || b.createdAt)) || "");
  return at >= bt ? a : b;
}

function mergePanelRecords(localRows, cloudRows, kind) {
  const map = new Map();
  (Array.isArray(localRows) ? localRows : []).forEach((record) => {
    const key = panelRecordKey(kind, record);
    map.set(key, record);
  });
  (Array.isArray(cloudRows) ? cloudRows : []).forEach((record) => {
    const key = panelRecordKey(kind, record);
    map.set(key, map.has(key) ? panelRecordNewer(map.get(key), record) : record);
  });
  return [...map.values()].sort((a, b) => String(b.createdAt || "").localeCompare(String(a.createdAt || "")));
}

async function ensurePanelRecordConversation() {
  if (!storage) return null;
  let conversation = null;
  try {
    conversation = await storage.getConversationBySessionId(PANEL_RECORD_SESSION_ID);
  } catch (error) {
    console.error("panel record conversation read error:", error && error.message ? error.message.slice(0, 500) : error);
  }
  if (conversation) return conversation;

  const now = new Date().toISOString();
  try {
    return await storage.createConversation({
      sessionId: PANEL_RECORD_SESSION_ID,
      visitorName: "RUTH Panel Kalıcı Kayıt",
      visitorPhone: "",
      visitorLabel: "Sistem",
      pageUrl: "/admin/",
      pageTitle: "İade ve Değişim Kalıcı Arşivi",
      status: "closed",
      unreadAdminCount: 0,
      lastMessageText: "İade/değişim kayıtları burada yedeklenir",
      lastCustomerMessageAt: "",
      lastAdminMessageAt: now,
      createdAt: now,
      updatedAt: now
    });
  } catch (error) {
    console.error("panel record conversation create error:", error && error.message ? error.message.slice(0, 500) : error);
    return null;
  }
}

function encodePanelRecord(kind, record) {
  return PANEL_RECORD_PREFIX + JSON.stringify({
    kind: normalizePanelRecordKind(kind),
    record,
    savedAt: new Date().toISOString(),
    version: 1
  });
}

function decodePanelRecord(body) {
  const raw = String(body || "");
  if (!raw.startsWith(PANEL_RECORD_PREFIX)) return null;
  try {
    const parsed = JSON.parse(raw.slice(PANEL_RECORD_PREFIX.length));
    if (!parsed || !parsed.record) return null;
    return {
      kind: normalizePanelRecordKind(parsed.kind),
      record: parsed.record,
      savedAt: parsed.savedAt || ""
    };
  } catch (error) {
    return null;
  }
}

async function archivePanelRecord(kind, record) {
  try {
    const conversation = await ensurePanelRecordConversation();
    if (!conversation) return { ok: false, error: "archive_conversation_unavailable" };
    const now = new Date().toISOString();
    await storage.addMessage({
      conversationId: conversation.id,
      sessionId: PANEL_RECORD_SESSION_ID,
      sender: "system",
      body: encodePanelRecord(kind, record),
      imageName: "",
      imageMime: "",
      imageData: "",
      createdAt: now
    });
    try {
      await storage.updateConversation(conversation.id, {
        status: "closed",
        unreadAdminCount: 0,
        lastMessageText: normalizePanelRecordKind(kind) === "return" ? "İade kaydı yedeklendi" : "Değişim kaydı yedeklendi",
        lastAdminMessageAt: now,
        updatedAt: now
      });
    } catch (updateError) {}
    return { ok: true, storage: storage.kind };
  } catch (error) {
    console.error("panel record archive error:", error && error.message ? error.message.slice(0, 800) : error);
    return { ok: false, error: error && error.message ? error.message : String(error) };
  }
}

async function loadArchivedPanelRecords(kind) {
  try {
    const conversation = storage && await storage.getConversationBySessionId(PANEL_RECORD_SESSION_ID);
    if (!conversation) return [];
    const messages = await storage.listMessages(conversation.id);
    return (messages || [])
      .map((message) => decodePanelRecord(message.body))
      .filter((item) => item && item.kind === normalizePanelRecordKind(kind) && item.record)
      .map((item) => item.record);
  } catch (error) {
    console.error("panel record archive list error:", error && error.message ? error.message.slice(0, 800) : error);
    return [];
  }
}

async function listExchangeRecordsPersistent() {
  const local = listExchangeRecords();
  const archived = await loadArchivedPanelRecords("exchange");
  return mergePanelRecords(local, archived, "exchange");
}

async function listReturnRecordsPersistent() {
  const local = listReturnRecords();
  const archived = await loadArchivedPanelRecords("return");
  return mergePanelRecords(local, archived, "return");
}


